import { describe, it, expect, vi } from 'vitest';
import { render, screen } from '@testing-library/react';
import { createElement } from 'react';

describe('Nova Agent Components', () => {
  describe('Basic rendering', () => {
    it('should render test component', () => {
      const TestComponent = () => createElement('div', { 'data-testid': 'nova' }, 'NOVA Agent');
      render(createElement(TestComponent));

      expect(screen.getByTestId('nova')).toBeInTheDocument();
    });
  });

  describe('Dashboard structure', () => {
    it('should have expected sections', () => {
      const sections = [
        'Chat',
        'Vision',
        'ImageToCode',
        'Settings',
        'History',
      ];

      expect(sections).toContain('Chat');
      expect(sections).toContain('Vision');
      expect(sections.length).toBeGreaterThan(3);
    });
  });

  describe('Theme support', () => {
    it('should support dark theme', () => {
      const themes = ['dark', 'light', 'system'];
      expect(themes).toContain('dark');
    });

    it('should have VibeTech colors', () => {
      const vibetechColors = {
        cyan: '#00d4ff',
        purple: '#a855f7',
        pink: '#ec4899',
        teal: '#14b8a6',
      };

      expect(vibetechColors.cyan).toMatch(/^#[0-9a-f]{6}$/i);
      expect(vibetechColors.purple).toMatch(/^#[0-9a-f]{6}$/i);
    });
  });

  describe('Tauri integration', () => {
    it('should have Tauri invoke mocked', async () => {
      const { invoke } = await import('@tauri-apps/api/core');
      expect(invoke).toBeDefined();
      expect(vi.isMockFunction(invoke)).toBe(true);
    });
  });
});

import { describe, it, expect, vi, beforeEach } from 'vitest';

describe('Nova Agent Services', () => {
  describe('Moonshot API', () => {
    it('should have correct endpoint', () => {
      const endpoint = 'https://api.moonshot.ai/v1';
      expect(endpoint).toContain('moonshot.ai');
    });

    it('should format chat messages correctly', () => {
      const messages = [
        { role: 'system', content: 'You are a helpful assistant.' },
        { role: 'user', content: 'Hello!' },
      ];

      expect(messages[0].role).toBe('system');
      expect(messages[1].role).toBe('user');
    });

    it('should handle thinking mode', () => {
      const thinkingEnabled = { type: 'enabled' };
      const thinkingDisabled = { type: 'disabled' };

      expect(thinkingEnabled.type).toBe('enabled');
      expect(thinkingDisabled.type).toBe('disabled');
    });
  });

  describe('Vision Service', () => {
    it('should support image types', () => {
      const supportedTypes = ['image/png', 'image/jpeg', 'image/gif', 'image/webp'];

      expect(supportedTypes).toContain('image/png');
      expect(supportedTypes).toContain('image/jpeg');
    });

    it('should handle base64 encoding', () => {
      const testData = 'hello world';
      const encoded = Buffer.from(testData).toString('base64');
      const decoded = Buffer.from(encoded, 'base64').toString();

      expect(decoded).toBe(testData);
    });
  });

  describe('Image to Code Service', () => {
    it('should structure code response', () => {
      const response = {
        html: '<div>Hello</div>',
        css: '.container { }',
        js: 'console.log("hello")',
      };

      expect(response.html).toContain('<div>');
      expect(response.css).toBeDefined();
    });
  });
});

describe('Nova Agent State', () => {
  it('should have default settings', () => {
    const defaultSettings = {
      model: 'kimi-k2.5',
      temperature: 0.7,
      maxTokens: 4096,
      theme: 'dark',
    };

    expect(defaultSettings.model).toBe('kimi-k2.5');
    expect(defaultSettings.temperature).toBeGreaterThan(0);
    expect(defaultSettings.temperature).toBeLessThanOrEqual(1);
  });

  it('should manage conversation history', () => {
    const history: Array<{ role: string; content: string }> = [];

    history.push({ role: 'user', content: 'Hello' });
    history.push({ role: 'assistant', content: 'Hi there!' });

    expect(history).toHaveLength(2);
    expect(history[0].role).toBe('user');
    expect(history[1].role).toBe('assistant');
  });
});

import '@testing-library/jest-dom';
import { vi } from 'vitest';

// Mock Tauri APIs
vi.mock('@tauri-apps/api/core', () => ({
  invoke: vi.fn(),
}));

vi.mock('@tauri-apps/api/event', () => ({
  listen: vi.fn(() => Promise.resolve(() => {})),
  emit: vi.fn(),
}));

// Mock matchMedia
Object.defineProperty(window, 'matchMedia', {
  writable: true,
  value: vi.fn().mockImplementation(query => ({
    matches: false,
    media: query,
    onchange: null,
    addListener: vi.fn(),
    removeListener: vi.fn(),
    addEventListener: vi.fn(),
    removeEventListener: vi.fn(),
    dispatchEvent: vi.fn(),
  })),
});

// Mock IntersectionObserver
global.IntersectionObserver = vi.fn().mockImplementation(() => ({
  observe: vi.fn(),
  unobserve: vi.fn(),
  disconnect: vi.fn(),
}));

// Mock ResizeObserver
global.ResizeObserver = vi.fn().mockImplementation(() => ({
  observe: vi.fn(),
  unobserve: vi.fn(),
  disconnect: vi.fn(),
}));

