import { invoke } from "@tauri-apps/api/core";
import {
	Code,
	Lightbulb,
	Loader2,
	RefreshCw,
	Search,
	TrendingUp,
} from "lucide-react";
import React, { useEffect, useState } from "react";

interface CodePattern {
	id: number;
	pattern_type: string;
	name: string;
	code_snippet: string;
	file_path: string;
	language: string;
	imports?: string;
	usage_count: number;
	last_used?: number;
	tags?: string;
	created_at: number;
}

interface CodeSuggestion {
	pattern: CodePattern;
	relevance_score: number;
	reason: string;
}

interface IndexStats {
	total_patterns: number;
	by_language: [string, number][];
	by_type: [string, number][];
	last_indexed?: number;
}

export default function PersonalCopilot() {
	const [stats, setStats] = useState<IndexStats | null>(null);
	const [suggestions, setSuggestions] = useState<CodeSuggestion[]>([]);
	const [searchQuery, setSearchQuery] = useState("");
	const [searchResults, setSearchResults] = useState<CodePattern[]>([]);
	const [isIndexing, setIsIndexing] = useState(false);
	const [isSearching, setIsSearching] = useState(false);
	const [selectedLanguage, _setSelectedLanguage] = useState<string>("");

	useEffect(() => {
		loadStats();
	}, []);

	const loadStats = async () => {
		try {
			const result = await invoke<IndexStats>("get_copilot_stats_command");
			setStats(result);
		} catch (error) {
			console.error("Failed to load stats:", error);
		}
	};

	const indexCodebase = async () => {
		setIsIndexing(true);
		try {
			const result = await invoke<string>("index_codebase_command", {
				rootPath: "C:\\dev",
				maxFiles: 2000,
			});
			console.log(result);
			await loadStats();
		} catch (error) {
			console.error("Indexing failed:", error);
		} finally {
			setIsIndexing(false);
		}
	};

	const searchPatterns = async () => {
		if (!searchQuery.trim()) return;

		setIsSearching(true);
		try {
			const results = await invoke<CodePattern[]>("search_patterns", {
				query: searchQuery,
				language: selectedLanguage || null,
				limit: 10,
			});
			setSearchResults(results);
		} catch (error) {
			console.error("Search failed:", error);
		} finally {
			setIsSearching(false);
		}
	};

	const _getSuggestions = async (context: string) => {
		try {
			const results = await invoke<CodeSuggestion[]>("get_suggestions", {
				context,
				language: selectedLanguage || null,
			});
			setSuggestions(results);
		} catch (error) {
			console.error("Failed to get suggestions:", error);
		}
	};

	const markPatternAsUsed = async (patternId: number) => {
		try {
			await invoke("use_pattern", { patternId });
			await loadStats();
		} catch (error) {
			console.error("Failed to mark pattern as used:", error);
		}
	};

	const copyToClipboard = (code: string) => {
		navigator.clipboard.writeText(code);
	};

	return (
		<div className="h-full flex flex-col bg-gray-900 text-white">
			{/* Header */}
			<div className="p-4 border-b border-gray-700">
				<div className="flex items-center justify-between mb-4">
					<div className="flex items-center gap-2">
						<Lightbulb className="w-6 h-6 text-yellow-400" />
						<h2 className="text-xl font-bold">Personal Copilot</h2>
					</div>
					<button
						onClick={indexCodebase}
						disabled={isIndexing}
						className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg disabled:opacity-50"
					>
						{isIndexing ? (
							<>
								<Loader2 className="w-4 h-4 animate-spin" />
								Indexing...
							</>
						) : (
							<>
								<RefreshCw className="w-4 h-4" />
								Index Codebase
							</>
						)}
					</button>
				</div>

				{/* Stats */}
				{stats && (
					<div className="grid grid-cols-3 gap-4 text-sm">
						<div className="bg-gray-800 p-3 rounded-lg">
							<div className="text-gray-400">Total Patterns</div>
							<div className="text-2xl font-bold">{stats.total_patterns}</div>
						</div>
						<div className="bg-gray-800 p-3 rounded-lg">
							<div className="text-gray-400">Languages</div>
							<div className="text-2xl font-bold">
								{stats.by_language.length}
							</div>
						</div>
						<div className="bg-gray-800 p-3 rounded-lg">
							<div className="text-gray-400">Pattern Types</div>
							<div className="text-2xl font-bold">{stats.by_type.length}</div>
						</div>
					</div>
				)}
			</div>

			{/* Search */}
			<div className="p-4 border-b border-gray-700">
				<div className="flex gap-2">
					<input
						type="text"
						value={searchQuery}
						onChange={(e) => setSearchQuery(e.target.value)}
						onKeyPress={(e) => e.key === "Enter" && searchPatterns()}
						placeholder="Search patterns..."
						className="flex-1 px-4 py-2 bg-gray-800 border border-gray-700 rounded-lg focus:outline-none focus:border-blue-500"
					/>
					<button
						onClick={searchPatterns}
						disabled={isSearching}
						className="px-4 py-2 bg-blue-600 hover:bg-blue-700 rounded-lg disabled:opacity-50"
					>
						{isSearching ? (
							<Loader2 className="w-4 h-4 animate-spin" />
						) : (
							<Search className="w-4 h-4" />
						)}
					</button>
				</div>
			</div>

			{/* Results */}
			<div className="flex-1 overflow-y-auto p-4">
				{searchResults.length > 0 && (
					<div className="space-y-4">
						<h3 className="text-lg font-semibold flex items-center gap-2">
							<Code className="w-5 h-5" />
							Search Results ({searchResults.length})
						</h3>
						{searchResults.map((pattern) => (
							<PatternCard
								key={pattern.id}
								pattern={pattern}
								onUse={() => markPatternAsUsed(pattern.id)}
								onCopy={() => copyToClipboard(pattern.code_snippet)}
							/>
						))}
					</div>
				)}

				{suggestions.length > 0 && (
					<div className="space-y-4 mt-6">
						<h3 className="text-lg font-semibold flex items-center gap-2">
							<TrendingUp className="w-5 h-5" />
							Suggestions
						</h3>
						{suggestions.map((suggestion, idx) => (
							<div key={idx} className="space-y-2">
								<div className="text-sm text-gray-400">
									{suggestion.reason} (Relevance:{" "}
									{(suggestion.relevance_score * 100).toFixed(0)}%)
								</div>
								<PatternCard
									pattern={suggestion.pattern}
									onUse={() => markPatternAsUsed(suggestion.pattern.id)}
									onCopy={() =>
										copyToClipboard(suggestion.pattern.code_snippet)
									}
								/>
							</div>
						))}
					</div>
				)}

				{stats?.total_patterns === 0 && (
					<div className="text-center py-12 text-gray-400">
						<Lightbulb className="w-16 h-16 mx-auto mb-4 opacity-50" />
						<p className="text-lg mb-2">No patterns indexed yet</p>
						<p className="text-sm">
							Click "Index Codebase" to start learning from your code
						</p>
					</div>
				)}
			</div>
		</div>
	);
}

interface PatternCardProps {
	pattern: CodePattern;
	onUse: () => void;
	onCopy: () => void;
}

function PatternCard({ pattern, onUse, onCopy }: PatternCardProps) {
	const [isExpanded, setIsExpanded] = useState(false);

	return (
		<div className="bg-gray-800 rounded-lg p-4 border border-gray-700 hover:border-gray-600 transition-colors">
			<div className="flex items-start justify-between mb-2">
				<div className="flex-1">
					<div className="flex items-center gap-2 mb-1">
						<span className="px-2 py-1 bg-blue-600 text-xs rounded">
							{pattern.pattern_type}
						</span>
						<span className="px-2 py-1 bg-gray-700 text-xs rounded">
							{pattern.language}
						</span>
						<span className="font-mono text-sm">{pattern.name}</span>
					</div>
					<div className="text-xs text-gray-400 truncate">
						{pattern.file_path}
					</div>
				</div>
				<div className="flex items-center gap-2">
					<span className="text-xs text-gray-400">
						Used {pattern.usage_count}x
					</span>
					<button
						onClick={onCopy}
						className="px-3 py-1 bg-gray-700 hover:bg-gray-600 text-xs rounded"
					>
						Copy
					</button>
					<button
						onClick={onUse}
						className="px-3 py-1 bg-blue-600 hover:bg-blue-700 text-xs rounded"
					>
						Use
					</button>
				</div>
			</div>

			<button
				onClick={() => setIsExpanded(!isExpanded)}
				className="text-sm text-blue-400 hover:text-blue-300"
			>
				{isExpanded ? "Hide" : "Show"} code
			</button>

			{isExpanded && (
				<pre className="mt-2 p-3 bg-gray-900 rounded text-xs overflow-x-auto">
					<code>{pattern.code_snippet}</code>
				</pre>
			)}

			{pattern.tags && (
				<div className="mt-2 flex gap-1 flex-wrap">
					{pattern.tags.split(",").map((tag, idx) => (
						<span key={idx} className="px-2 py-1 bg-gray-700 text-xs rounded">
							{tag.trim()}
						</span>
					))}
				</div>
			)}
		</div>
	);
}

import { invoke } from "@tauri-apps/api/core";
import { motion } from "framer-motion";
import { Camera, Loader2 } from "lucide-react";
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { useToast } from "@/hooks/use-toast";
import { analyzeScreenshot } from "@/services/visionService";

interface ScreenshotResult {
	path: string;
	timestamp: number;
	width: number;
	height: number;
}

interface ScreenshotButtonProps {
	onAnalysisComplete?: (analysis: string, imagePath: string) => void;
	customPrompt?: string;
}

export function ScreenshotButton({
	onAnalysisComplete,
	customPrompt,
}: ScreenshotButtonProps) {
	const [isCapturing, setIsCapturing] = useState(false);
	const [isAnalyzing, setIsAnalyzing] = useState(false);
	const { toast } = useToast();

	const handleScreenshot = async () => {
		try {
			setIsCapturing(true);

			// Capture screenshot using Tauri command
			const result = await invoke<ScreenshotResult>("capture_screenshot");

			toast({
				title: "Screenshot Captured",
				description: `Saved to: ${result.path}`,
			});

			setIsCapturing(false);
			setIsAnalyzing(true);

			// Analyze screenshot with vision service
			const analysis = await analyzeScreenshot(result.path, {
				prompt: customPrompt,
			});

			toast({
				title: "Analysis Complete",
				description: "Screenshot analyzed successfully",
			});

			// Call callback if provided
			if (onAnalysisComplete) {
				onAnalysisComplete(analysis.analysis, result.path);
			}

			// Also show analysis in toast
			toast({
				title: "Vision Analysis",
				description: analysis.analysis.slice(0, 200) + "...",
				duration: 10000,
			});
		} catch (error) {
			console.error("Screenshot error:", error);
			toast({
				title: "Error",
				description:
					error instanceof Error
						? error.message
						: "Failed to capture or analyze screenshot",
				variant: "destructive",
			});
		} finally {
			setIsCapturing(false);
			setIsAnalyzing(false);
		}
	};

	return (
		<Button
			onClick={handleScreenshot}
			disabled={isCapturing || isAnalyzing}
			className="bg-purple-500 hover:bg-purple-600 text-white shadow-lg shadow-purple-500/20 relative overflow-hidden"
			size="icon"
			title="Capture & Analyze Screenshot"
		>
			{isCapturing || isAnalyzing ? (
				<motion.div
					animate={{ rotate: 360 }}
					transition={{ duration: 1, repeat: Infinity, ease: "linear" }}
				>
					<Loader2 className="w-4 h-4" />
				</motion.div>
			) : (
				<Camera className="w-4 h-4" />
			)}

			{/* Animated background on hover */}
			<motion.div
				className="absolute inset-0 bg-white/10"
				initial={{ scale: 0, opacity: 0 }}
				whileHover={{ scale: 1.5, opacity: 0.3 }}
				transition={{ duration: 0.3 }}
				style={{ borderRadius: "50%" }}
			/>
		</Button>
	);
}

import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardFooter,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useAdmin } from '@/context/AdminContext';
import { useToast } from '@/hooks/use-toast';
import { Eye, EyeOff, Shield } from 'lucide-react';
import { useState, type FormEvent } from 'react';

interface AdminLoginProps {
  onClose?: () => void;
}

const AdminLogin = ({ onClose }: AdminLoginProps) => {
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const { login } = useAdmin();
  const { toast } = useToast();

  const handleLogin = async (e: FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    try {
      const success = await login(password);
      if (success) {
        toast({
          title: 'Admin Access Granted',
          description: 'You now have access to all premium tools.',
          variant: 'default',
        });
        if (onClose) onClose();
      } else {
        toast({
          title: 'Invalid Password',
          description: 'Please check your admin password and try again.',
          variant: 'destructive',
        });
      }
    } catch (_error) {
      toast({
        title: 'Login Error',
        description: 'An error occurred during login.',
        variant: 'destructive',
      });
    } finally {
      setIsLoading(false);
      setPassword('');
    }
  };

  return (
    <Card className="glass-card border-[rgba(185,51,255,0.2)] max-w-md mx-auto">
      <CardHeader className="text-center">
        <div className="flex justify-center mb-4">
          <Shield className="h-12 w-12 text-[color:var(--c-cyan)]" />
        </div>
        <CardTitle className="text-white">Admin Access</CardTitle>
        <CardDescription className="text-gray-300">
          Enter admin password to access all premium tools
        </CardDescription>
      </CardHeader>

      <form onSubmit={handleLogin}>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="password" className="text-white">
              Password
            </Label>
            <div className="relative">
              <Input
                id="password"
                type={showPassword ? 'text' : 'password'}
                value={password}
                onChange={(e: React.ChangeEvent<HTMLInputElement>) => setPassword(e.target.value)}
                placeholder="Enter admin password"
                className="bg-aura-background/50 border-[rgba(185,51,255,0.3)] text-white pr-10"
                required
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                onClick={() => setShowPassword(!showPassword)}
              >
                {showPassword ? (
                  <EyeOff className="h-4 w-4 text-gray-400" />
                ) : (
                  <Eye className="h-4 w-4 text-gray-400" />
                )}
              </Button>
            </div>
          </div>
        </CardContent>

        <CardFooter className="flex gap-2">
          <Button type="submit" className="flex-1" disabled={isLoading || !password.trim()}>
            {isLoading ? 'Verifying...' : 'Login as Admin'}
          </Button>
          {onClose && (
            <Button type="button" variant="outline" onClick={onClose} className="flex-1">
              Cancel
            </Button>
          )}
        </CardFooter>
      </form>
    </Card>
  );
};

export default AdminLogin;

import { Loader2, PlusCircle } from "lucide-react";
import { useState } from "react";
import { toast } from "sonner";
import { Button } from "@/components/ui/button";
import {
	Dialog,
	DialogContent,
	DialogDescription,
	DialogFooter,
	DialogHeader,
	DialogTitle,
	DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { Textarea } from "@/components/ui/textarea";
import { useTaskManager } from "@/hooks/useNovaData";

interface CreateTaskDialogProps {
	onTaskCreated?: () => void;
	trigger?: React.ReactNode;
}

export function CreateTaskDialog({
	onTaskCreated,
	trigger,
}: CreateTaskDialogProps) {
	const [open, setOpen] = useState(false);
	const [loading, setLoading] = useState(false);
	const { createTask } = useTaskManager();

	const [title, setTitle] = useState("");
	const [description, setDescription] = useState("");
	const [priority, setPriority] = useState("medium");

	const handleSubmit = async (e: React.FormEvent) => {
		e.preventDefault();
		if (!title.trim()) return;

		setLoading(true);
		try {
			const result = await createTask({
				title,
				description: description || undefined,
				priority,
			});

			if (result.isDuplicate) {
				toast.warning("Duplicate task detected", {
					description: "This task already exists.",
				});
			} else {
				toast.success("Task created successfully");
				setOpen(false);
				setTitle("");
				setDescription("");
				setPriority("medium");
				onTaskCreated?.();
			}
		} catch (error) {
			toast.error("Failed to create task");
			console.error(error);
		} finally {
			setLoading(false);
		}
	};

	return (
		<Dialog open={open} onOpenChange={setOpen}>
			<DialogTrigger asChild>
				{trigger ?? (
