	// Set page title if provided
	useEffect(() => {
		if (title) {
			document.title = `${title} | Vibe Tech`;
		}
	}, [title]);

	// Use reduced animations on mobile for better performance
	const shouldReduceAnimations = isMobile ?? !features.webGL.check();

	// Dynamically adjust particle count based on device capability
	const optimizedParticleCount = shouldReduceAnimations
		? Math.floor(particleCount * 0.3)
		: particleCount;

	// Prepare default metadata
	const siteTitle = title
		? `${title} | Vibe Tech`
		: "Vibe Tech | Creating innovative digital solutions";
	const siteDescription =
		description ||
		"Creating innovative digital solutions with a focus on design and functionality";
	const siteKeywords =
