import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Checkbox } from "@/components/ui/checkbox";
import type { Todo } from "./types";

interface TodoItemProps {
	todo: Todo;
	onToggleComplete: (id: string) => void;
	onDelete: (id: string) => void;
	onEdit?: (id: string, updates: Partial<Todo>) => void;
}

const priorityColors = {
	low: "bg-green-100 text-green-800 border-green-300",
	medium: "bg-yellow-100 text-yellow-800 border-yellow-300",
	high: "bg-red-100 text-red-800 border-red-300",
};

const TodoItem = ({
	todo,
	onToggleComplete,
	onDelete,
	onEdit: onEdit,
}: TodoItemProps) => {
	const getTodoDueStatus = (dueDate?: Date) => {
		if (!dueDate) return null;

		const today = new Date();
		today.setHours(0, 0, 0, 0);

		const dueDateCopy = new Date(dueDate);
		dueDateCopy.setHours(0, 0, 0, 0);

		const diffTime = dueDateCopy.getTime() - today.getTime();
		const diffDays = diffTime / (1000 * 60 * 60 * 24);

		if (diffDays < 0) return "overdue";
		if (diffDays === 0) return "today";
		if (diffDays <= 2) return "soon";
		return "future";
	};

	const getDueStatusClass = (status: string | null) => {
		if (!status) return "";

		switch (status) {
			case "overdue":
				return "text-red-500";
			case "today":
				return "text-yellow-500";
			case "soon":
				return "text-amber-400";
			default:
				return "text-aura-textSecondary";
		}
	};

	return (
		<div className="flex items-start justify-between py-3 border-b border-aura-accent/5">
			<div className="flex items-start gap-3 flex-1">
				<Checkbox
					id={`todo-${todo.id}`}
					checked={todo.completed}
					onCheckedChange={() => onToggleComplete(todo.id)}
					className="border-aura-accent/50 data-[state=checked]:bg-aura-accent mt-1"
				/>
				<div className="flex flex-col gap-2 flex-1">
					<label
						htmlFor={`todo-${todo.id}`}
						className={`text-sm ${
							todo.completed
								? "line-through text-aura-textSecondary"
								: "text-aura-text"
						}`}
					>
						{todo.text}
					</label>

					<div className="flex items-center gap-2 flex-wrap">
						<Badge variant="outline" className="text-xs">
							{todo.category}
						</Badge>
						<Badge className={`text-xs ${priorityColors[todo.priority]}`}>
							{todo.priority}
						</Badge>
						{todo.dueDate && (
							<div
								className={`text-xs flex items-center ${getDueStatusClass(getTodoDueStatus(todo.dueDate))}`}
							>
								<Calendar className="h-3 w-3 mr-1 inline" />
								{format(todo.dueDate, "MMM d, yyyy")}
							</div>
						)}
					</div>
				</div>
			</div>
			<Button
				variant="ghost"
				size="icon"
				onClick={() => onDelete(todo.id)}
				className="h-8 w-8 text-aura-textSecondary hover:text-red-500"
			>
				<Trash2 className="h-4 w-4" />
			</Button>
		</div>
	);
};

export default TodoItem;

import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { ExternalLink, Star } from 'lucide-react';
import React from 'react';

interface AffiliateLinkProps {
  name: string;
  url: string;
  description: string;
  commission?: string;
  category: string;
}

const AffiliateLink = ({
  name,
  url,
  description,
  commission,
  category,
}: AffiliateLinkProps) => {
  const handleClick = () => {
    // Track affiliate link clicks
    if (typeof window !== 'undefined' && (window as any).gtag) {
      (window as any).gtag('event', 'affiliate_click', {
        event_category: 'affiliate',
        event_label: name,
        value: category,
      });
    }

    // Open in new tab
    window.open(url, '_blank', 'noopener,noreferrer');
  };

  return (
    <div className="group relative overflow-hidden rounded-lg border border-border/50 bg-card/50 backdrop-blur-sm p-4 transition-all duration-300 hover:border-aura-accent/50 hover:bg-card/80 hover:shadow-lg hover:shadow-aura-accent/20">
      <div className="flex items-start justify-between gap-4">
        <div className="flex-1">
          <div className="flex items-center gap-2 mb-2">
            <h4 className="font-semibold text-foreground group-hover:text-aura-accent transition-colors">
              {name}
            </h4>
            <Badge variant="secondary" className="text-xs">
              {category}
            </Badge>
          </div>

          <p className="text-sm text-muted-foreground mb-3 line-clamp-2">{description}</p>

          {commission && (
            <div className="flex items-center gap-1 mb-3">
              <Star className="h-3 w-3 text-yellow-500 fill-yellow-500" />
              <span className="text-xs text-aura-accent font-medium">{commission}</span>
            </div>
          )}

          <Button
            onClick={handleClick}
            size="sm"
            className="bg-gradient-to-r from-aura-accent to-aura-accent/80 hover:from-aura-accent/90 hover:to-aura-accent/70 text-white shadow-lg hover:shadow-aura-accent/25 transition-all duration-300"
          >
            <span>Get Started</span>
            <ExternalLink className="ml-2 h-3 w-3" />
          </Button>
        </div>
      </div>

      {/* Hover effect overlay */}
      <div className="absolute inset-0 bg-gradient-to-r from-aura-accent/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none" />
    </div>
  );
};

export default AffiliateLink;

import { fireEvent, render, screen } from "@testing-library/react";
import { beforeEach, describe, expect, it, vi } from "vitest";
import { SidebarProvider, useSidebar } from "../sidebar";

// Mock useIsMobile hook
vi.mock("@/hooks/use-mobile", () => ({
	useIsMobile: vi.fn(),
}));

import { useIsMobile } from "@/hooks/use-mobile";

// Test component that consumes the context
const TestComponent = () => {
	const { state, toggleSidebar, open } = useSidebar();
	return (
		<div>
			<span data-testid="sidebar-state">{state}</span>
			<span data-testid="sidebar-open">{open ? "true" : "false"}</span>
			<button onClick={toggleSidebar} data-testid="toggle-btn">
				Toggle
			</button>
		</div>
	);
};

describe("Sidebar Component", () => {
	beforeEach(() => {
		vi.clearAllMocks();
		(useIsMobile as any).mockReturnValue(false); // Default to desktop
		// Clear cookies
		document.cookie.split(";").forEach((c) => {
			document.cookie = c
				.replace(/^ +/, "")
				.replace(/=.*/, "=;expires=" + new Date().toUTCString() + ";path=/");
		});
	});

	it("renders children correctly", () => {
		render(
			<SidebarProvider>
				<div data-testid="child">Child Content</div>
			</SidebarProvider>,
		);
		expect(screen.getByTestId("child")).toBeInTheDocument();
	});

	it("provides correct default context values", () => {
		render(
			<SidebarProvider defaultOpen={true}>
				<TestComponent />
			</SidebarProvider>,
		);

		expect(screen.getByTestId("sidebar-state")).toHaveTextContent("expanded");
		expect(screen.getByTestId("sidebar-open")).toHaveTextContent("true");
	});

	it("toggles sidebar state on button click", () => {
		render(
			<SidebarProvider defaultOpen={true}>
				<TestComponent />
			</SidebarProvider>,
		);

		const toggleBtn = screen.getByTestId("toggle-btn");
		fireEvent.click(toggleBtn);

		expect(screen.getByTestId("sidebar-state")).toHaveTextContent("collapsed");
		expect(screen.getByTestId("sidebar-open")).toHaveTextContent("false");
	});

	it("sets cookie when state changes", () => {
		render(
			<SidebarProvider defaultOpen={true}>
				<TestComponent />
			</SidebarProvider>,
		);

		const toggleBtn = screen.getByTestId("toggle-btn");
		fireEvent.click(toggleBtn);

		expect(document.cookie).toContain("sidebar:state=false");
	});

	it("handles mobile state correctly", () => {
		(useIsMobile as any).mockReturnValue(true);

		render(
			<SidebarProvider>
				<TestComponent />
			</SidebarProvider>,
		);

		// Initial state might differ on mobile depending on implementation,
		// but toggling should still work for mobile menu
		const toggleBtn = screen.getByTestId("toggle-btn");
		fireEvent.click(toggleBtn);

		// Check if openMobile logic is triggered (impl detail, but observable via context/renders)
		// For now, just ensure no crash
		expect(screen.getByTestId("toggle-btn")).toBeInTheDocument();
	});
});

