import { useFrame } from "@react-three/fiber";
import { useMemo, useRef } from "react";
import * as THREE from "three";
import type { ConnectionLineProps } from "./types";

const ConnectionLine = ({
	startPos,
	endPos,
	color,
	threshold,
}: ConnectionLineProps) => {
	const lineRef = useRef<THREE.Line>(null);
	const positions = useMemo(() => new Float32Array(6), []);
	const lineColor = useMemo(() => new THREE.Color(color), [color]);

	useFrame(({ clock }) => {
		if (lineRef.current && startPos.current && endPos.current) {
			// Update line vertices based on particle positions
			positions[0] = startPos.current.position.x;
			positions[1] = startPos.current.position.y;
			positions[2] = startPos.current.position.z;

			positions[3] = endPos.current.position.x;
			positions[4] = endPos.current.position.y;
			positions[5] = endPos.current.position.z;

			const positionAttribute = lineRef.current.geometry.attributes
				.position as THREE.BufferAttribute;
			positionAttribute.needsUpdate = true;

			// Calculate distance between particles
			const distance = new THREE.Vector3(
				startPos.current.position.x,
				startPos.current.position.y,
				startPos.current.position.z,
			).distanceTo(
				new THREE.Vector3(
					endPos.current.position.x,
					endPos.current.position.y,
					endPos.current.position.z,
				),
			);

			// Pulse effect for line opacity
			const pulseFactor = (Math.sin(clock.elapsedTime * 2) + 1) * 0.2 + 0.1; // 0.1 to 0.5 range

			// Only show lines for particles within threshold distance
			if (distance < threshold) {
				lineRef.current.visible = true;

				// Adjust opacity based on distance and pulse
				const opacity = (1 - distance / threshold) * pulseFactor;
				if (lineRef.current.material instanceof THREE.LineBasicMaterial) {
					lineRef.current.material.opacity = opacity;

					// Subtle color shift based on time
					const hueShift = Math.sin(clock.elapsedTime * 0.2) * 0.05;
					lineRef.current.material.color
						.copy(lineColor)
						.offsetHSL(hueShift, 0, 0);
				}
			} else {
				lineRef.current.visible = false;
			}
		}
	});

	return (
		<primitive object={new THREE.Line()} ref={lineRef}>
			<bufferGeometry>
				<bufferAttribute
					attach="attributes-position"
					args={[positions, 3]}
				/>
			</bufferGeometry>
			<lineBasicMaterial color={color} transparent opacity={0.2} />
		</primitive>
	);
};

export default ConnectionLine;

import { useMemo } from "react";
import * as THREE from "three";
import ConnectionLine from "./ConnectionLine";
import Particle from "./Particle";
import type { ParticleNetworkProps } from "./types";

const deterministicNoise = (seed: number): number => {
	const raw = Math.sin(seed * 12.9898) * 43758.5453;
	return raw - Math.floor(raw);
};

const ParticleNetwork = ({
	count = 15,
	connectionThreshold = 2,
}: ParticleNetworkProps) => {
	const particleRefs = useMemo(
		() =>
			Array.from({ length: count }, () => ({ current: null as THREE.Mesh | null })),
		[count],
	);

	// Generate a more visually pleasing color palette
	const generateColor = (index: number) => {
		const colors = [
			"#28f0ff", // cyan
			"#9c57ff", // purple
			"#00ffcc", // teal
			"#ff68f9", // pink
			"#4d9aff", // blue
		];
		return colors[index % colors.length] ?? colors[0]!;
	};

	// Generate particle positions with more intentional distribution
	const particleData = Array.from({ length: count }, (_, i) => {
		// Create a more organized distribution but with some randomness
		const angle = (i / count) * Math.PI * 2;
		const radius = 2 + deterministicNoise(i + 1) * 3;
		const x = Math.cos(angle) * radius * (0.8 + deterministicNoise(i + 2) * 0.4);
		const y = (deterministicNoise(i + 3) - 0.5) * 10;
		const z = Math.sin(angle) * radius * (0.8 + deterministicNoise(i + 4) * 0.4);

		return {
			position: [x, y, z] as [number, number, number],
			color: generateColor(i),
			speed: (deterministicNoise(i + 5) + 0.1) * 0.007, // Slightly faster movement
		};
	});

	return (
		<>
			{/* Render particles */}
			{particleData.map((data, i) => (
				<Particle
					key={`particle-${i}`}
					position={data.position}
					color={data.color}
					speed={data.speed}
					x={0}
					y={0}
					radius={0}
					directionX={0}
					directionY={0}
					ref={(el) => {
						particleRefs[i]!.current = el;
					}}
				/>
			))}

			{/* Render connection lines with improved connection logic */}
			{particleData.map((_, i) =>
				particleData.slice(i + 1).map((_, j) => {
					const index1 = i;
					const index2 = i + j + 1;

					const data1 = particleData[index1];
					const data2 = particleData[index2];
					if (!data1 || !data2) return null;

					// Only create connections between nearby particles to reduce clutter
					const distance = new THREE.Vector3(
						data1.position[0],
						data1.position[1],
						data1.position[2],
					).distanceTo(
						new THREE.Vector3(
							data2.position[0],
							data2.position[1],
							data2.position[2],
						),
					);

					if (distance < connectionThreshold * 1.2) {
						return (
							<ConnectionLine
								key={`connection-${index1}-${index2}`}
								startPos={particleRefs[index1]!}
								endPos={particleRefs[index2]!}
								color="#28f0ff"
								threshold={connectionThreshold}
								startX={0}
								startY={0}
								endX={0}
								endY={0}
								opacity={0}
							/>
						);
					}
					return null;
				}),
			)}
		</>
	);
};

export default ParticleNetwork;

import { useRef, useMemo } from "react";
import { useFrame } from "@react-three/fiber";
import * as THREE from "three";
import { Text } from "@react-three/drei";

interface RAGVisualizationProps {
  results: Array<{ 
    id: string;
    distance: number; // 0 to 1, where 0 is identical
    metadata: {
      file_path?: string;
      [key: string]: unknown;
    };
  }>;
  query?: string;
}

const RAGVisualization = ({ results, query = "Query" }: RAGVisualizationProps) => {
  const groupRef = useRef<THREE.Group>(null);

  // Rotation animation
  useFrame((state, delta) => {
    if (groupRef.current) {
      groupRef.current.rotation.y += delta * 0.1;
    }
  });

  // Calculate node positions based on relevance
  // Center is (0,0,0)
  // Results are satellites at distance based on their 'distance' score
  const nodes = useMemo(() => {
    return results.map((result, i) => {
      // Relevance score (inverted distance: 1.0 = perfect match, 0.0 = no match)
      // Assuming distance is cosine distance (0-1 usually, can be 0-2)
      // Let's normalize visually: closer = better
      const visualDistance = 2 + (result.distance * 5); // 2 units min, up to 7 units away

      // Distribute in a sphere
      const phi = Math.acos(-1 + (2 * i) / results.length);
      const theta = Math.sqrt(results.length * Math.PI) * phi;

      const x = visualDistance * Math.cos(theta) * Math.sin(phi);
      const y = visualDistance * Math.sin(theta) * Math.sin(phi);
      const z = visualDistance * Math.cos(phi);

      return {
        ...result,
        position: new THREE.Vector3(x, y, z),
        relevance: (1 - result.distance).toFixed(2)
      };
    });
  }, [results]);

  return (
    <group ref={groupRef}>
      {/* Central Query Node */}
      <mesh position={[0, 0, 0]}>
        <sphereGeometry args={[0.8, 32, 32]} />
        <meshStandardMaterial color="#9c57ff" emissive="#9c57ff" emissiveIntensity={0.5} />
      </mesh>
      <Text
        position={[0, 1.2, 0]}
        fontSize={0.5}
        color="white"
        anchorX="center"
        anchorY="middle"
      >
        {query}
      </Text>

      {/* Result Nodes */}
      {nodes.map((node, i) => (
        <group key={node.id} position={node.position}>
          {/* Node Sphere */}
          <mesh>
            <sphereGeometry args={[0.4, 32, 32]} />
            <meshStandardMaterial 
              color={node.distance < 0.3 ? "#28f0ff" : "#4d9aff"} 
              emissive={node.distance < 0.3 ? "#28f0ff" : "#4d9aff"}
              emissiveIntensity={0.5}
            />
          </mesh>

          {/* Connection Line to Center */}
          <line>
            <bufferGeometry>
              <bufferAttribute
                attach="attributes-position"
                args={[new Float32Array([0, 0, 0, -node.position.x, -node.position.y, -node.position.z]), 3]}
              />
            </bufferGeometry>
            <lineBasicMaterial color="#ffffff" transparent opacity={0.2} />
          </line>

          {/* Label */}
          <Text
            position={[0, 0.6, 0]}
            fontSize={0.3}
            color="#a0a0a0"
            anchorX="center"
            anchorY="middle"
          >
            {node.metadata.file_path?.split(/[\\/]/).pop() || "Unknown"}
            {`\n(${node.relevance})`}
          </Text>
        </group>
      ))}

      {/* Ambient light for the scene */}
      <ambientLight intensity={0.5} />
      <pointLight position={[10, 10, 10]} intensity={1} />
    </group>
  );
};

export default RAGVisualization;

import { Canvas } from "@react-three/fiber";
import { useState } from "react";
import ParticleNetwork from "./ParticleNetwork";
import RAGVisualization from "./RAGVisualization";
import type { ParticleNetworkCanvasProps } from "./types";

const checkWebglSupport = (): boolean => {
	try {
		const canvas = document.createElement("canvas");
		const gl = canvas.getContext("webgl") ?? canvas.getContext("experimental-webgl");
		return !!gl;
	} catch (_e) {
		return false;
	}
};

// Canvas wrapper component with error handling
const ParticleNetworkCanvas = ({
	className,
	particleCount = 15,
	opacity = 0.08,
	connectionThreshold = 2,
	ragResults,
	query,
}: ParticleNetworkCanvasProps) => {
	const [webglSupported] = useState(checkWebglSupport);
	const [hasError, setHasError] = useState(false);

	// Don't render if WebGL is not supported or there's an error
	if (!webglSupported || hasError) {
		// Return a simple fallback without 3D
		return (
			<div
				className={`absolute inset-0 pointer-events-none ${className ?? ""}`}
				style={{ opacity }}
			>
				{/* Simple CSS animation fallback */}
				<div className="absolute inset-0 bg-gradient-to-br from-purple-900/10 via-transparent to-cyan-900/10 animate-pulse" />
			</div>
		);
	}

	return (
		<div
			className={`absolute inset-0 pointer-events-none ${className ?? ""}`}
			style={{ opacity }}
		>
			<Canvas
				camera={{ position: [0, 0, 5], fov: 75 }}
				onError={() => setHasError(true)}
				onCreated={(state) => {
					// Handle context loss
					const gl = state.gl;
					const canvas = gl.domElement;

					canvas.addEventListener("webglcontextlost", (event) => {
						event.preventDefault();
						setHasError(true);
					});

					canvas.addEventListener("webglcontextrestored", () => {
						setHasError(false);
					});
				}}
			>
				{ragResults && ragResults.length > 0 ? (
					<RAGVisualization results={ragResults} query={query} />
				) : (
					<ParticleNetwork
						count={particleCount}
						connectionThreshold={connectionThreshold}
					/>
				)}
			</Canvas>
		</div>
	);
};

export default ParticleNetworkCanvas;

import { useBreakpoints } from '@/hooks/use-breakpoints';
import { useBrowserCapabilities } from '@/hooks/use-browser-capabilities';
import { cn } from '@/lib/utils';
import * as React from 'react';

type ResponsiveContainerProps = React.HTMLAttributes<HTMLDivElement> & {
  as?: React.ElementType;
  maxWidth?: 'xs' | 'sm' | 'md' | 'lg' | 'xl' | '2xl' | 'full' | 'none';
  padded?: boolean;
  centered?: boolean;
  adaptForTouch?: boolean;
};

const ResponsiveContainer = React.forwardRef<HTMLDivElement, ResponsiveContainerProps>(
  (
    {
      className,
      children,
      as: Component = 'div',
      maxWidth = 'xl',
      padded = true,
      centered = true,
      adaptForTouch = true,
      ...props
    },
    ref,
  ) => {
    // Get current breakpoint
    const { current, isMobile: _isMobile } = useBreakpoints();
    const { isTouchDevice } = useBrowserCapabilities();

    // Calculate appropriate padding based on screen size
    const getPadding = () => {
      if (!padded) return '';

      // Add extra padding for touch devices if requested
      const touchExtraPadding = adaptForTouch && isTouchDevice ? 'py-2' : '';

      switch (current) {
        case 'xs':
          return `px-4 ${touchExtraPadding}`;
        case 'sm':
          return `px-6 ${touchExtraPadding}`;
        default:
          return `px-4 sm:px-6 md:px-8 ${touchExtraPadding}`;
      }
    };

    // Calculate max-width based on prop
    const getMaxWidth = () => {
      switch (maxWidth) {
        case 'xs':
          return 'max-w-xs';
        case 'sm':
          return 'max-w-screen-sm';
        case 'md':
          return 'max-w-screen-md';
        case 'lg':
          return 'max-w-screen-lg';
        case 'xl':
          return 'max-w-screen-xl';
        case '2xl':
          return 'max-w-screen-2xl';
        case 'full':
          return 'max-w-full';
        case 'none':
          return '';
        default:
          return 'max-w-screen-xl';
      }
    };

    // Add touch-friendly classes if needed
    const getTouchClasses = () => {
      if (adaptForTouch && isTouchDevice) {
        return 'touch-manipulation'; // CSS touch-action property
      }
      return '';
    };

    const ComponentToRender = Component as any;
    return (
      <ComponentToRender
        ref={ref}
        className={cn(
          getMaxWidth(),
          getPadding(),
          getTouchClasses(),
          centered && 'mx-auto',
          'w-full',
          className,
        )}
        {...props}
      >
        {children}
      </ComponentToRender>
    );
  },
);

ResponsiveContainer.displayName = 'ResponsiveContainer';

export { ResponsiveContainer };

