} from "react";

interface AdminContextType {
	isAdmin: boolean;
	login: (password: string) => Promise<boolean>;
	logout: () => Promise<void>;
	checkAdminStatus: () => boolean;
}

const AdminContext = createContext<AdminContextType | undefined>(undefined);

const ADMIN_PASSWORD = "vibe2024admin"; // In production, this would be handled more securely

export const AdminProvider = ({ children }: { children: ReactNode }) => {
	const [isAdmin, setIsAdmin] = useState<boolean>(false);
	const [store, setStore] = useState<Store | null>(null);

	useEffect(() => {
		const initStore = async () => {
			try {
				const newStore = await Store.load("store.json");
				setStore(newStore);

				const adminSession = await newStore.get<string>(
					"vibetech_admin_session",
				);
				if (adminSession === "authenticated") {
					setIsAdmin(true);
				}
			} catch (error) {
				console.error("Failed to initialize store:", error);
			}
		};

		initStore();
	}, []);

	const login = async (password: string): Promise<boolean> => {
		if (password === ADMIN_PASSWORD) {
			setIsAdmin(true);
			if (store) {
				try {
					await store.set("vibetech_admin_session", "authenticated");
					await store.save();
				} catch (error) {
					console.error("Failed to save session:", error);
				}
			}
			return true;
		}
		return false;
	};

	const logout = async () => {
		setIsAdmin(false);
		if (store) {
			try {
				await store.delete("vibetech_admin_session");
				await store.save();
			} catch (error) {
				console.error("Failed to clear session:", error);
			}
		}
	};

	const checkAdminStatus = (): boolean => {
		return isAdmin;
	};

	return (
		<AdminContext.Provider value={{ isAdmin, login, logout, checkAdminStatus }}>
			{children}
		</AdminContext.Provider>
	);
};

export const useAdmin = (): AdminContextType => {
	const context = useContext(AdminContext);
	if (!context) {
		throw new Error("useAdmin must be used within an AdminProvider");
	}
	return context;
};

import {
	createContext,
	type ReactNode,
	useContext,
	useEffect,
	useState,
} from "react";
import { toast } from "@/hooks/use-toast";

export interface Notification {
	id: string;
	title: string;
	message: string;
	timestamp: Date;
	read: boolean;
	type: "info" | "success" | "warning" | "error";
}

interface NotificationsContextType {
	notifications: Notification[];
	unreadCount: number;
	addNotification: (
		notification: Omit<Notification, "id" | "timestamp" | "read">,
	) => void;
	markAsRead: (id: string) => void;
	markAllAsRead: () => void;
	removeNotification: (id: string) => void;
	clearAllNotifications: () => void;
}

const NotificationsContext = createContext<
	NotificationsContextType | undefined
>(undefined);

export const useNotifications = () => {
	const context = useContext(NotificationsContext);
	if (context === undefined) {
		throw new Error(
			"useNotifications must be used within a NotificationsProvider",
		);
	}
	return context;
};

export const NotificationsProvider = ({
	children,
}: {
	children: ReactNode;
}) => {
	const [notifications, setNotifications] = useState<Notification[]>(() => {
		// eslint-disable-next-line electron-security/no-localstorage-electron
		const storedNotifications = localStorage.getItem("notifications");
		if (!storedNotifications) {
			return [];
		}

		try {
			const parsedNotifications = JSON.parse(storedNotifications);
			return parsedNotifications.map((notification: any) => ({
				...notification,
				timestamp: new Date(notification.timestamp),
			})) as Notification[];
		} catch (error) {
			console.error("Failed to parse notifications from localStorage:", error);
			return [];
		}
	});

	// Calculate unread count
	const unreadCount = notifications.filter(
		(notification) => !notification.read,
	).length;

	// Update localStorage whenever notifications change
	useEffect(() => {
		// eslint-disable-next-line electron-security/no-localstorage-electron
		localStorage.setItem("notifications", JSON.stringify(notifications));
	}, [notifications]);

	// Add a new notification
	const addNotification = (
		notification: Omit<Notification, "id" | "timestamp" | "read">,
	) => {
		const newNotification: Notification = {
			...notification,
			id: Date.now().toString(),
			timestamp: new Date(),
			read: false,
		};

		setNotifications((prev) => [newNotification, ...prev]);

		// Show a toast for the new notification
		toast({
			title: notification.title,
			description: notification.message,
			variant: notification.type === "error" ? "destructive" : "default",
		});
	};

	// Mark a notification as read
	const markAsRead = (id: string) => {
		setNotifications((prev) =>
			prev.map((notification) =>
				notification.id === id ? { ...notification, read: true } : notification,
			),
		);
	};

	// Mark all notifications as read
	const markAllAsRead = () => {
		setNotifications((prev) =>
			prev.map((notification) => ({ ...notification, read: true })),
		);
	};

	// Remove a notification
	const removeNotification = (id: string) => {
		setNotifications((prev) =>
			prev.filter((notification) => notification.id !== id),
		);
	};

	// Clear all notifications
	const clearAllNotifications = () => {
		setNotifications([]);
	};

	return (
		<NotificationsContext.Provider
			value={{
				notifications,
				unreadCount,
				addNotification,
				markAsRead,
				markAllAsRead,
				removeNotification,
				clearAllNotifications,
			}}
		>
			{children}
		</NotificationsContext.Provider>
	);
};

import {
	createContext,
	type ReactNode,
	useContext,
	useEffect,
	useState,
} from "react";

type Theme = "dark" | "light" | "system";

interface ThemeProviderProps {
	children: ReactNode;
	attribute?: string;
	defaultTheme?: Theme;
	enableSystem?: boolean;
	disableTransitionOnChange?: boolean;
}

const ThemeContext = createContext<{
	theme: Theme;
	setTheme: (theme: Theme) => void;
}>({
	theme: "system",
	setTheme: () => null,
});

export const ThemeProvider = ({
	children,
	attribute = "data-theme",
	defaultTheme = "system",
	enableSystem = false,
	disableTransitionOnChange = false,
}: ThemeProviderProps) => {
	const [theme, setTheme] = useState<Theme>(defaultTheme);

	useEffect(() => {
		const root = window.document.documentElement;

		// Remove current class
		root.classList.remove("light", "dark");

		// Add new theme class
		if (theme === "system" && enableSystem) {
			const systemTheme = window.matchMedia("(prefers-color-scheme: dark)")
				.matches
				? "dark"
				: "light";
			root.classList.add(systemTheme);
			root.setAttribute(attribute, systemTheme);
		} else {
			root.classList.add(theme);
			root.setAttribute(attribute, theme);
		}

		if (disableTransitionOnChange) {
			// Temporarily disable transitions
			root.classList.add("no-transitions");
			setTimeout(() => root.classList.remove("no-transitions"), 0);
		}
	}, [theme, attribute, enableSystem, disableTransitionOnChange]);

	// Listen for system theme changes
	useEffect(() => {
		if (!enableSystem) return;

		const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");

		const handleChange = () => {
			if (theme === "system") {
				const systemTheme = mediaQuery.matches ? "dark" : "light";
				const root = window.document.documentElement;
				root.classList.remove("light", "dark");
				root.classList.add(systemTheme);
				root.setAttribute(attribute, systemTheme);
			}
		};

		mediaQuery.addEventListener("change", handleChange);
		return () => mediaQuery.removeEventListener("change", handleChange);
	}, [theme, attribute, enableSystem]);

	return (
		<ThemeContext.Provider value={{ theme, setTheme }}>
			{children}
		</ThemeContext.Provider>
	);
};

export const useTheme = () => useContext(ThemeContext);

export default ThemeProvider;

import { exec } from "child_process";
