import { features } from '@/lib/feature-detection';
import React from 'react';

interface BrowserCapabilities {
  supportsWebGL: boolean;
  supportsWebP: boolean;
  isTouchDevice: boolean;
  prefersReducedMotion: boolean;
  isLowPowerMode: boolean;
  batteryLevel?: number;
}

export function useBrowserCapabilities(): BrowserCapabilities {
  const [capabilities, setCapabilities] = React.useState<BrowserCapabilities>({
    supportsWebGL: true,
    supportsWebP: true,
    isTouchDevice: false,
    prefersReducedMotion: false,
    isLowPowerMode: false,
  });

  React.useEffect(() => {
    // Detect features
    const supportsWebGL = features.webGL.check();
    const supportsWebP = features.webP.check();
    const isTouchDevice = features.touchScreen.check();

    // Check for reduced motion preference
    const prefersReducedMotion = window.matchMedia('(prefers-reduced-motion: reduce)').matches;

    // Detect if device might be in low power mode (various heuristics)
    let isLowPowerMode = false;
    let batteryLevel: number | undefined;

    // Try to get battery info if available
    if ('getBattery' in navigator) {
      (navigator as any)
        .getBattery()
        .then((battery: unknown) => {
          isLowPowerMode = (battery as any).charging === false && (battery as any).level < 0.2;
          batteryLevel = (battery as any).level;

          setCapabilities((prev) => ({
            ...prev,
            isLowPowerMode,
            batteryLevel,
          }));
        })
        .catch(() => {
          // Battery API failed, continue without it
        });
    }

    setCapabilities({
      supportsWebGL,
      supportsWebP,
      isTouchDevice,
      prefersReducedMotion,
      isLowPowerMode,
      batteryLevel,
    });
  }, []);

  return capabilities;
}

import { act, renderHook, waitFor } from "@testing-library/react";
import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { useDeviceType, useIsMobile, useIsPortrait } from "./use-mobile";

describe("useIsMobile", () => {
	let matchMediaMock: any;
	let listeners: ((event: any) => void)[] = [];

	beforeEach(() => {
		listeners = [];
		matchMediaMock = vi.fn((query: string) => ({
			matches: false,
			media: query,
			addEventListener: vi.fn((_event: string, listener: (e: any) => void) => {
				listeners.push(listener);
			}),
			removeEventListener: vi.fn(
				(_event: string, listener: (e: any) => void) => {
					listeners = listeners.filter((l) => l !== listener);
				},
			),
			dispatchEvent: vi.fn(),
			onchange: null,
			addListener: vi.fn(),
			removeListener: vi.fn(),
		}));

		Object.defineProperty(window, "matchMedia", {
			writable: true,
			configurable: true,
			value: matchMediaMock,
		});
	});

	afterEach(() => {
		listeners = [];
		vi.restoreAllMocks();
	});

	it("should return false by default during SSR", () => {
		const { result } = renderHook(() => useIsMobile());
		expect(result.current).toBe(false);
	});

	it("should return true when viewport is mobile size", async () => {
		matchMediaMock.mockImplementation((query: string) => ({
			matches: true,
			media: query,
			addEventListener: vi.fn((_event: string, listener: (e: any) => void) => {
				listeners.push(listener);
			}),
			removeEventListener: vi.fn(),
			dispatchEvent: vi.fn(),
			onchange: null,
			addListener: vi.fn(),
			removeListener: vi.fn(),
		}));

		const { result } = renderHook(() => useIsMobile());

		await waitFor(() => {
			expect(result.current).toBe(true);
