	};
}

export const useSystemMonitor = () => {
	const [systemInfo, setSystemInfo] = useState<SystemInfo | null>(null);
	const [isMonitoring, setIsMonitoring] = useState(false);

	// Listen for IPC messages from the backend
	useEffect(() => {
		const unlisten = listen("ipc-message", (event) => {
			const msg = event.payload as any;

			// Check if this is a command response from desktop-commander-v3
			if (msg.type === "command_result" && msg.payload?.result?.cpu) {
				// It seems we got a system info payload
				setSystemInfo({
					cpu: msg.payload.result.cpu,
					mem: msg.payload.result.mem,
					os: msg.payload.result.os,
				});
			}
		});

		return () => {
			unlisten.then((f) => f());
		};
	}, []);

	// Function to trigger a manual update (though backend does this automatically now)
	const refreshSystemInfo = useCallback(async () => {
		// We can invoke the same command request logic from frontend if needed
		// But since main.rs is looping, we might just wait.
		// For now, let's rely on the backend loop we set up in Phase 3.
		setIsMonitoring(true);
	}, []);

	return { systemInfo, isMonitoring, refreshSystemInfo };
};

/**
 * Utility for browser feature detection that provides graceful degradation
 */

// Helper to safely check if a browser feature exists
export const featureExists = (featureName: string): boolean => {
  try {
    // Check for features in different potential locations
    return !!(
      (window as any)[featureName] ||
      (navigator as any)[featureName] ||
      (document as any)[featureName] ||
      // For CSS features
      (CSS?.supports && CSS.supports(featureName))
    );
  } catch (e) {
    console.warn(`Feature detection for ${featureName} failed:`, e);
    return false;
  }
};

// Common features with fallback information
export const features = {
  webGL: {
    check: () => {
      try {
        const canvas = document.createElement('canvas');
        return !!(
          window.WebGLRenderingContext &&
          (canvas.getContext('webgl') || canvas.getContext('experimental-webgl'))
        );
      } catch (_e) {
        return false;
      }
    },
    fallback: 'Static images instead of 3D rendering',
  },
  webP: {
    check: () => {
      const elem = document.createElement('canvas');
      if (elem.getContext && elem.getContext('2d')) {
        // was able to get 2d context
        return elem.toDataURL('image/webp').indexOf('data:image/webp') === 0;
      }
      return false;
    },
    fallback: 'PNG/JPG images',
  },
  touchScreen: {
    check: () => {
      return 'ontouchstart' in window || navigator.maxTouchPoints > 0;
    },
    fallback: 'Mouse-optimized interface',
  },
  // Add more feature checks as needed
};

// Hook to use feature detection in components
export const useFeatureDetection = () => {
  return {
    check: featureExists,
    features,
  };
};

