describe("getScreenSize", () => {
	let originalInnerWidth: number;
	let originalInnerHeight: number;

	beforeEach(() => {
		originalInnerWidth = window.innerWidth;
		originalInnerHeight = window.innerHeight;
	});

	afterEach(() => {
		Object.defineProperty(window, "innerWidth", {
			writable: true,
			configurable: true,
			value: originalInnerWidth,
		});
		Object.defineProperty(window, "innerHeight", {
			writable: true,
			configurable: true,
			value: originalInnerHeight,
		});
	});

	it("should return current screen dimensions", () => {
		Object.defineProperty(window, "innerWidth", {
			writable: true,
			configurable: true,
			value: 1024,
		});
		Object.defineProperty(window, "innerHeight", {
			writable: true,
			configurable: true,
			value: 768,
		});

		const size = getScreenSize();

		expect(size.width).toBe(1024);
		expect(size.height).toBe(768);
		expect(size.isPortrait).toBe(false);
	});

	it("should detect portrait orientation", () => {
		Object.defineProperty(window, "innerWidth", {
			writable: true,
			configurable: true,
			value: 768,
		});
		Object.defineProperty(window, "innerHeight", {
			writable: true,
			configurable: true,
			value: 1024,
		});

		const size = getScreenSize();

		expect(size.isPortrait).toBe(true);
	});

	it("should detect landscape orientation", () => {
		Object.defineProperty(window, "innerWidth", {
			writable: true,
			configurable: true,
			value: 1024,
		});
		Object.defineProperty(window, "innerHeight", {
			writable: true,
			configurable: true,
			value: 768,
		});

		const size = getScreenSize();

		expect(size.isPortrait).toBe(false);
	});

	it("should handle mobile portrait dimensions", () => {
		Object.defineProperty(window, "innerWidth", {
			writable: true,
			configurable: true,
			value: 375,
		});
		Object.defineProperty(window, "innerHeight", {
			writable: true,
			configurable: true,
			value: 667,
		});

		const size = getScreenSize();

		expect(size.width).toBe(375);
		expect(size.height).toBe(667);
		expect(size.isPortrait).toBe(true);
	});
});

describe("isTouchDevice", () => {
	let originalOntouchstart: any;
	let originalMaxTouchPoints: number;

	beforeEach(() => {
		originalOntouchstart = (window as any).ontouchstart;
		originalMaxTouchPoints = navigator.maxTouchPoints;
	});

	afterEach(() => {
		if (originalOntouchstart === undefined) {
			delete (window as any).ontouchstart;
		} else {
			(window as any).ontouchstart = originalOntouchstart;
		}

		Object.defineProperty(navigator, "maxTouchPoints", {
			writable: true,
			configurable: true,
			value: originalMaxTouchPoints,
		});
	});

	it("should detect touch via ontouchstart", () => {
		(window as any).ontouchstart = null;

		const result = isTouchDevice();

		expect(result).toBe(true);
	});

	it("should detect touch via maxTouchPoints", () => {
		delete (window as any).ontouchstart;

		Object.defineProperty(navigator, "maxTouchPoints", {
			writable: true,
			configurable: true,
			value: 5,
		});

		const result = isTouchDevice();

		expect(result).toBe(true);
	});

	it("should return false for non-touch devices", () => {
		delete (window as any).ontouchstart;

		Object.defineProperty(navigator, "maxTouchPoints", {
			writable: true,
			configurable: true,
			value: 0,
		});

		const result = isTouchDevice();

		expect(result).toBe(false);
	});
});

