const ChatInterface = () => {
	const [messages, setMessages] = useState<ChatMessage[]>([]);
	const [input, setInput] = useState("");
	const [isLoading, setIsLoading] = useState(false);
	const [agentState, setAgentState] = useState<AgentState | null>(null);
	const scrollRef = useRef<HTMLDivElement>(null);

	useEffect(() => {
		loadAgentStatus();
		// Add initial greeting
		setMessages([
			{
				role: "assistant",
				content:
					"Hello! I'm NOVA, your Neural Omnipresent Virtual Assistant. How can I help you today?",
				timestamp: Date.now(),
			},
		]);
	}, []);

	useEffect(() => {
		if (scrollRef.current) {
			scrollRef.current.scrollIntoView({ behavior: "smooth" });
		}
	}, [messages]);

	const loadAgentStatus = async () => {
		try {
			const status = await AgentService.getStatus();
			setAgentState(status);
		} catch (error) {
			console.error("Failed to load agent status:", error);
		}
	};

	const handleSend = async () => {
		if (!input.trim() || isLoading) return;

		const userMessage: ChatMessage = {
			role: "user",
			content: input,
			timestamp: Date.now(),
		};

		setMessages((prev) => [...prev, userMessage]);
		setInput("");
		setIsLoading(true);

		try {
			const response = await AgentService.chat(input);

			const assistantMessage: ChatMessage = {
				role: "assistant",
				content: response,
				timestamp: Date.now(),
			};

			setMessages((prev) => [...prev, assistantMessage]);
			loadAgentStatus(); // Refresh status after interaction
		} catch (error) {
			console.error("Chat error:", error);
			const errorMessage: ChatMessage = {
				role: "system",
				content: `Error: ${error instanceof Error ? error.message : String(error)}`,
				timestamp: Date.now(),
			};
			setMessages((prev) => [...prev, errorMessage]);
		} finally {
			setIsLoading(false);
		}
