interface RAGResult {
	id: string;
	distance: number;
	metadata: {
		file_path?: string;
		[key: string]: unknown;
	};
}

const Dashboard = () => {
	const {
		activeTab,
		setActiveTab,
		isLoading,
		error,
		activities,
		metrics,
		loadDashboardData,
		clearActivity,
		runDiagnostics: _runDiagnostics,
		isPro,
	} = useDashboardData();

	const { trackEvent } = useAnalytics();
	const [ragQuery, setRagQuery] = useState("Project Context");
	const [ragResults, setRagResults] = useState<RAGResult[]>([]);

	// Fetch initial RAG context for visualization
	useEffect(() => {
		const fetchRagContext = async () => {
			try {
				const results = await invoke<RAGResult[]>("rag_search", {
					query: ragQuery,
					topK: 8,
				});
				setRagResults(results);
			} catch (e) {
				console.error("Failed to fetch RAG context for visualization", e);
			}
		};
		fetchRagContext();
	}, [ragQuery]);

	// Track dashboard page view with additional details
	useEffect(() => {
		trackEvent("dashboard_view", {
			category: "Dashboard",
			label: isPro ? "Pro Dashboard" : "Standard Dashboard",
			customDimensions: {
				is_pro_user: isPro,
				active_tab: activeTab,
				activity_count: activities.length,
				has_error: error !== null,
			},
		});
	}, [isPro, activeTab, activities.length, error, trackEvent]);

	// Simplified animation variant
	const containerVariants = {
		hidden: { opacity: 0 },
		visible: {
			opacity: 1,
			transition: {
				duration: 0.3,
			},
		},
	};

	return (
		<div className="min-h-screen bg-aura-darkBg pb-16 relative overflow-hidden">
			{/* Background effects with further reduced intensity */}
			<DashboardBackground ragResults={ragResults} query={ragQuery} />

			<NavBar />

			<motion.div
				className="max-w-7xl mx-auto px-4 pt-24 relative z-10"
				variants={containerVariants}
				initial="hidden"
				animate={!isLoading ? "visible" : "hidden"}
			>
				<DashboardTopbar onRefresh={loadDashboardData} isPro={isPro} />

				{isLoading ? (
					<DashboardSkeleton />
				) : error ? (
					<DashboardErrorState error={error} onRetry={loadDashboardData} />
				) : (
					<DashboardContent
						activities={activities}
						metrics={metrics}
						activeTab={activeTab}
						setActiveTab={setActiveTab}
						onClearActivity={clearActivity}
						isPro={isPro}
					/>
				)}
			</motion.div>

			{/* Keep the Toaster component here to handle toast notifications */}
			<Toaster />
		</div>
	);
};

