/**
 * ExtensionManager
 *
 * Plugin architecture for DeepCode Editor inspired by VS Code
 * Manages extension lifecycle, commands, and API
 *
 * Based on 2025 best practices:
 * - Interface-based extension contracts
 * - Dependency resolution with circular detection
 * - Extension context with subscriptions
 * - Command registration and execution
 * - Extension API exposure
 */

export interface ExtensionManifest {
  id: string;
  name: string;
  version: string;
  publisher: string;
  main: string;
  displayName?: string;
  description?: string;
  categories?: string[];
  keywords?: string[];
  icon?: string;
  repository?: string;
  license?: string;
  activationEvents?: string[];
  extensionDependencies?: string[];
}

export interface ExtensionContext {
  extensionId: string;
  subscriptions: { dispose: () => void }[];
  registerCommand: (commandId: string, handler: (...args: any[]) => any) => void;
  api: ExtensionAPI;
}

export interface ExtensionAPI {
  workspace: any;
  window: any;
  commands: any;
}

export interface Extension {
  id: string;
  manifest: ExtensionManifest;
  isActive: boolean;
}

type ActivateFunction = (
  context: ExtensionContext,
) => void | Promise<void | { deactivate?: () => void | Promise<void> }>;
type DeactivateFunction = () => void | Promise<void>;

interface ExtensionInternal extends Extension {
  activateFn?: ActivateFunction;
  deactivateFn?: DeactivateFunction;
  context?: ExtensionContext;
}

export class ExtensionManager {
  private extensions = new Map<string, ExtensionInternal>();
  private commands = new Map<string, (...args: any[]) => any>();

  /**
   * Register a new extension
   */
  registerExtension(manifest: ExtensionManifest, activateFn?: ActivateFunction): Extension {
    // Validate manifest
    if (!manifest.id || manifest.id.trim() === '') {
      throw new Error('Invalid extension manifest');
    }

    if (!manifest.name || manifest.name.trim() === '') {
      throw new Error('Invalid extension manifest');
    }

    if (!manifest.version) {
      throw new Error('Invalid extension manifest');
    }

    if (!manifest.publisher) {
      throw new Error('Invalid extension manifest');
    }

    if (!manifest.main) {
      throw new Error('Invalid extension manifest');
    }

    // Check for duplicates
    if (this.extensions.has(manifest.id)) {
      throw new Error('Extension already registered');
    }

    const extension: ExtensionInternal = {
      id: manifest.id,
      manifest,
      isActive: false,
      activateFn,
    };

    this.extensions.set(manifest.id, extension);

    return {
      id: extension.id,
      manifest: extension.manifest,
      isActive: extension.isActive,
    };
  }

  /**
   * Activate an extension
   */
  async activateExtension(extensionId: string): Promise<void> {
    const extension = this.extensions.get(extensionId);

    if (!extension) {
      throw new Error('Extension not found');
    }

    if (extension.isActive) {
      return; // Already active, no-op
    }

    // Check and activate dependencies first
    if (extension.manifest.extensionDependencies) {
      await this.activateDependencies(extensionId, extension.manifest.extensionDependencies, []);
    }

    // Create extension context
    const context: ExtensionContext = {
      extensionId: extension.id,
      subscriptions: [],
      registerCommand: (commandId: string, handler: (...args: any[]) => any) => {
        this.commands.set(commandId, handler);
        context.subscriptions.push({
          dispose: () => this.commands.delete(commandId),
        });
      },
      api: {
        workspace: {
          workspaceFolders: [],
          getConfiguration: (_section?: string) => ({}),
          openFolder: async (_path: string) => Promise.resolve(),
          getFolders: () => [],
        },
        window: {
          showInformationMessage: (message: string) => console.log(message),
          showErrorMessage: (message: string) => console.error(message),
        },
        commands: {
          registerCommand: (commandId: string, handler: (...args: any[]) => any) => {
            context.registerCommand(commandId, handler);
          },
          executeCommand: async (commandId: string, ...args: any[]) => {
            return this.executeCommand(commandId, ...args);
          },
        },
      },
    };

    extension.context = context;

    // Call activate function and capture deactivate function
    if (extension.activateFn) {
      const result = extension.activateFn(context);
      if (result && typeof result.then === 'function') {
        const awaitedResult = await result;
        if (awaitedResult && awaitedResult.deactivate) {
          extension.deactivateFn = awaitedResult.deactivate;
        }
      } else if (result && (result as any).deactivate) {
        extension.deactivateFn = (result as any).deactivate;
      }
    }

    extension.isActive = true;
  }

  /**
   * Activate extension dependencies
   */
  private async activateDependencies(
    extensionId: string,
    dependencies: string[],
    visited: string[],
  ): Promise<void> {
    // Check for circular dependencies
    if (visited.includes(extensionId)) {
      throw new Error('Circular dependency detected');
    }

    const newVisited = [...visited, extensionId];

    for (const depId of dependencies) {
      const depExtension = this.extensions.get(depId);

      if (!depExtension) {
        throw new Error('Dependency not found');
      }

      // Recursively activate dependencies
      if (depExtension.manifest.extensionDependencies) {
        await this.activateDependencies(
          depId,
          depExtension.manifest.extensionDependencies,
          newVisited,
        );
      }

      // Activate dependency if not already active
      if (!depExtension.isActive) {
        await this.activateExtension(depId);
      }
    }
  }

  /**
   * Deactivate an extension
   */
  async deactivateExtension(extensionId: string): Promise<void> {
    const extension = this.extensions.get(extensionId);

    if (!extension) {
      throw new Error('Extension not found');
    }

    if (!extension.isActive) {
      return; // Already inactive, no-op
    }

    // Call deactivate function if exists
    if (extension.deactivateFn) {
      const result = extension.deactivateFn();
      if (result && typeof result.then === 'function') {
        await result;
      }
    }

    // Dispose all subscriptions
    if (extension.context) {
      for (const subscription of extension.context.subscriptions) {
        subscription.dispose();
      }
      extension.context.subscriptions = [];
    }

    extension.isActive = false;
  }

  /**
   * Uninstall an extension
   */
  uninstallExtension(extensionId: string): void {
    const extension = this.extensions.get(extensionId);

    if (!extension) {
      throw new Error('Extension not found');
    }

    // Deactivate first if active (synchronous version)
    if (extension.isActive) {
      // Call deactivate function if exists
      if (extension.deactivateFn) {
        extension.deactivateFn();
      }

      // Dispose all subscriptions
      if (extension.context) {
        for (const subscription of extension.context.subscriptions) {
          subscription.dispose();
        }
        extension.context.subscriptions = [];
      }

      extension.isActive = false;
    }

    this.extensions.delete(extensionId);
  }

  /**
   * Get extension by ID
   */
  getExtension(extensionId: string): Extension {
    const extension = this.extensions.get(extensionId);

    if (!extension) {
      throw new Error('Extension not found');
    }

    return {
      id: extension.id,
      manifest: extension.manifest,
      isActive: extension.isActive,
    };
  }

  /**
   * Get all extensions
   */
  getAllExtensions(): Extension[] {
    return Array.from(this.extensions.values()).map((ext) => ({
      id: ext.id,
      manifest: ext.manifest,
      isActive: ext.isActive,
    }));
  }

  /**
   * Get active extensions
   */
  getActiveExtensions(): Extension[] {
    return this.getAllExtensions().filter((ext) => ext.isActive);
  }

  /**
   * Get all registered commands
   */
  getCommands(): string[] {
    return Array.from(this.commands.keys());
  }

  /**
   * Execute a command
   */
  async executeCommand(commandId: string, ...args: any[]): Promise<any> {
    const handler = this.commands.get(commandId);

    if (!handler) {
      throw new Error('Command not found');
    }

    const result = handler(...args);
    if (module && typeof (module as any).deactivate === 'function') {
      await (module as any).deactivate();
    }
    if (result && typeof result.then === 'function') {
      return await result;
    }

    return result;
  }

  /**
   * Dispose all resources
   */
  dispose(): void {
    // Deactivate all active extensions
    for (const extension of this.extensions.values()) {
      if (extension.isActive) {
        // Call deactivate function if exists
        if (extension.deactivateFn) {
          extension.deactivateFn();
        }

        // Dispose all subscriptions
        if (extension.context) {
          for (const subscription of extension.context.subscriptions) {
            subscription.dispose();
          }
          extension.context.subscriptions = [];
        }

        extension.isActive = false;
      }
    }

    // Clear all data
    this.extensions.clear();
    this.commands.clear();
  }

  /**
   * Set deactivate function for extension (for testing)
   */
  setDeactivateFunction(extensionId: string, deactivateFn: DeactivateFunction): void {
    const extension = this.extensions.get(extensionId);
    if (extension) {
      extension.deactivateFn = deactivateFn;
    }
  }
}

import type {
	ExtensionInstallation,
	ExtensionReview,
	ExtensionSearchQuery,
	ExtensionSearchResult,
	MarketplaceEvent,
	MarketplaceEventHandler,
	MarketplaceEventType,
	MarketplaceExtension,
} from "../types/marketplace";

/**
 * ExtensionRegistry
 * Manages marketplace extensions, search, ratings, and installation tracking
 */
export class ExtensionRegistry {
	private extensions = new Map<string, MarketplaceExtension>();
	private installations = new Map<string, ExtensionInstallation>();
	private reviews = new Map<string, ExtensionReview[]>();
	private eventHandlers = new Map<
		MarketplaceEventType,
		Set<MarketplaceEventHandler>
	>();

	/**
	 * Register or update a marketplace extension
	 */
	register(extension: MarketplaceExtension): void {
		this.extensions.set(extension.manifest.id, extension);
	}

	/**
	 * Get extension by ID
	 */
	getExtension(extensionId: string): MarketplaceExtension | undefined {
		return this.extensions.get(extensionId);
	}

	/**
	 * Search extensions
	 */
	search(query: ExtensionSearchQuery): ExtensionSearchResult {
		let results = Array.from(this.extensions.values());

		// Filter by query text
		if (query.query) {
			const searchTerm = query.query.toLowerCase();
			results = results.filter(
				(ext) =>
					ext.manifest.name.toLowerCase().includes(searchTerm) ||
					ext.manifest.description?.toLowerCase().includes(searchTerm) ||
					ext.manifest.keywords?.some((kw) =>
						kw.toLowerCase().includes(searchTerm),
					),
			);
		}

		// Filter by category
		if (query.category) {
			results = results.filter((ext) =>
				ext.manifest.categories?.includes(query.category!),
			);
		}

		// Filter featured only
		if (query.featuredOnly) {
			results = results.filter((ext) => ext.metadata.featured);
		}

		// Filter verified only
		if (query.verifiedOnly) {
			results = results.filter((ext) => ext.metadata.verified);
		}

		// Sort results
		results = this.sortResults(results, query.sortBy ?? "relevance");

		// Pagination
		const page = query.page ?? 1;
		const pageSize = query.pageSize ?? 20;
		const startIndex = (page - 1) * pageSize;
		const endIndex = startIndex + pageSize;

		const paginatedResults = results.slice(startIndex, endIndex);

		this.emit("searchPerformed", { query, resultCount: results.length });

		return {
			extensions: paginatedResults,
			totalCount: results.length,
			page,
			pageSize,
			hasMore: endIndex < results.length,
		};
	}

	/**
	 * Sort search results
	 */
	private sortResults(
		results: MarketplaceExtension[],
		sortBy: "relevance" | "downloads" | "rating" | "recent" | "name",
	): MarketplaceExtension[] {
		switch (sortBy) {
			case "downloads":
				return results.sort(
					(a, b) => b.metadata.downloads - a.metadata.downloads,
				);

			case "rating":
				return results.sort((a, b) => b.metadata.rating - a.metadata.rating);

			case "recent":
				return results.sort(
					(a, b) =>
						new Date(b.metadata.lastUpdated).getTime() -
						new Date(a.metadata.lastUpdated).getTime(),
				);

			case "name":
				return results.sort((a, b) =>
					a.manifest.name.localeCompare(b.manifest.name),
				);

			case "relevance":
			default:
				// For relevance, prioritize: featured > rating > downloads
				return results.sort((a, b) => {
					if (a.metadata.featured !== b.metadata.featured) {
						return a.metadata.featured ? -1 : 1;
					}
					if (Math.abs(a.metadata.rating - b.metadata.rating) > 0.5) {
						return b.metadata.rating - a.metadata.rating;
					}
					return b.metadata.downloads - a.metadata.downloads;
				});
		}
	}

	/**
	 * Mark extension as installed
	 */
	markAsInstalled(
		extensionId: string,
		version: string,
		source: "marketplace" | "local" | "git" = "marketplace",
	): void {
		const installation: ExtensionInstallation = {
			extensionId,
			version,
			installedAt: new Date().toISOString(),
			source,
			autoUpdate: true,
			status: "installed",
		};

		this.installations.set(extensionId, installation);
		this.emit("extensionInstalled", { extensionId, version });
	}

	/**
	 * Mark extension as uninstalled
	 */
	markAsUninstalled(extensionId: string): void {
		this.installations.delete(extensionId);
		this.emit("extensionUninstalled", { extensionId });
	}

	/**
	 * Check if extension is installed
	 */
	isInstalled(extensionId: string): boolean {
		return this.installations.has(extensionId);
	}

	/**
	 * Get installed version
	 */
	getInstalledVersion(extensionId: string): string | undefined {
		return this.installations.get(extensionId)?.version;
	}

	/**
	 * Get all installed extensions
	 */
	getInstalledExtensions(): ExtensionInstallation[] {
		return Array.from(this.installations.values());
	}

	/**
	 * Get available updates
	 */
	getAvailableUpdates(): {
		extensionId: string;
		currentVersion: string;
		availableVersion: string;
	}[] {
		const updates: {
			extensionId: string;
			currentVersion: string;
			availableVersion: string;
		}[] = [];

		for (const [extensionId, installation] of this.installations) {
			const marketplaceExt = this.extensions.get(extensionId);
			if (
				marketplaceExt &&
				marketplaceExt.manifest.version !== installation.version
			) {
				// Simple version comparison (in production, use semver)
				if (
					this.compareVersions(
						marketplaceExt.manifest.version,
						installation.version,
					) > 0
				) {
					updates.push({
						extensionId,
						currentVersion: installation.version,
						availableVersion: marketplaceExt.manifest.version,
					});
				}
			}
		}

		return updates;
	}

	/**
	 * Check if specific extension has update
	 */
	hasUpdate(extensionId: string): boolean {
		const installation = this.installations.get(extensionId);
		if (!installation) return false;

		const marketplaceExt = this.extensions.get(extensionId);
		if (!marketplaceExt) return false;

		return (
			this.compareVersions(
				marketplaceExt.manifest.version,
				installation.version,
			) > 0
		);
	}

	/**
	 * Simple version comparison (production should use semver library)
	 */
	private compareVersions(v1: string, v2: string): number {
		const parts1 = v1.split(".").map(Number);
		const parts2 = v2.split(".").map(Number);

		for (let i = 0; i < Math.max(parts1.length, parts2.length); i++) {
			const num1 = parts1[i] ?? 0;
			const num2 = parts2[i] ?? 0;

			if (num1 > num2) return 1;
			if (num1 < num2) return -1;
		}

		return 0;
	}

	/**
	 * Add a review
	 */
	addReview(review: ExtensionReview): void {
		if (!this.reviews.has(review.extensionId)) {
			this.reviews.set(review.extensionId, []);
		}

		this.reviews.get(review.extensionId)!.push(review);
		this.emit("reviewSubmitted", { extensionId: review.extensionId, review });
	}

	/**
	 * Get reviews for extension
	 */
	getReviews(extensionId: string): ExtensionReview[] {
		return this.reviews.get(extensionId) ?? [];
	}

	/**
	 * Calculate average rating from reviews
	 */
	getAverageRating(extensionId: string): number {
		const reviews = this.reviews.get(extensionId);
		if (!reviews || reviews.length === 0) return 0;

		const totalRating = reviews.reduce((sum, review) => sum + review.rating, 0);
		return totalRating / reviews.length;
	}

	/**
	 * Mark review as helpful
	 */
	markReviewHelpful(reviewId: string): void {
		for (const reviews of this.reviews.values()) {
			const review = reviews.find((r) => r.id === reviewId);
			if (review) {
				review.helpfulCount++;
				return;
			}
		}
	}

	/**
	 * Get featured extensions
	 */
	getFeaturedExtensions(): MarketplaceExtension[] {
		return Array.from(this.extensions.values()).filter(
			(ext) => ext.metadata.featured,
		);
	}

	/**
	 * Get popular extensions (by downloads)
	 */
	getPopularExtensions(limit = 10): MarketplaceExtension[] {
		return Array.from(this.extensions.values())
			.sort((a, b) => b.metadata.downloads - a.metadata.downloads)
			.slice(0, limit);
	}

	/**
	 * Get recently updated extensions
	 */
	getRecentlyUpdated(limit = 10): MarketplaceExtension[] {
		return Array.from(this.extensions.values())
			.sort(
				(a, b) =>
					new Date(b.metadata.lastUpdated).getTime() -
					new Date(a.metadata.lastUpdated).getTime(),
			)
			.slice(0, limit);
	}

	/**
	 * Get top rated extensions
	 */
	getTopRated(limit = 10): MarketplaceExtension[] {
		return Array.from(this.extensions.values())
			.filter((ext) => ext.metadata.ratingCount >= 10) // Minimum ratings threshold
			.sort((a, b) => b.metadata.rating - a.metadata.rating)
			.slice(0, limit);
	}

	/**
	 * Register event handler
	 */
	on(event: MarketplaceEventType, handler: MarketplaceEventHandler): void {
		if (!this.eventHandlers.has(event)) {
			this.eventHandlers.set(event, new Set());
		}
		this.eventHandlers.get(event)!.add(handler);
	}

	/**
	 * Unregister event handler
	 */
	off(event: MarketplaceEventType, handler: MarketplaceEventHandler): void {
		const handlers = this.eventHandlers.get(event);
		if (handlers) {
			handlers.delete(handler);
		}
	}

	/**
	 * Emit event to all registered handlers
	 */
	private emit(type: MarketplaceEventType, data: any): void {
		const event: MarketplaceEvent = {
			type,
			extensionId: data.extensionId,
			timestamp: Date.now(),
			data,
		};

		const handlers = this.eventHandlers.get(type);
		if (handlers) {
			handlers.forEach((handler) => handler(event));
		}
	}

	/**
	 * Clear all data (for testing)
	 */
	clear(): void {
		this.extensions.clear();
		this.installations.clear();
		this.reviews.clear();
	}

	/**
	 * Get all extensions
	 */
	getAllExtensions(): MarketplaceExtension[] {
		return Array.from(this.extensions.values());
	}

	/**
	 * Get extension count
	 */
	getExtensionCount(): number {
		return this.extensions.size;
	}

	/**
	 * Get total downloads across all extensions
	 */
	getTotalDownloads(): number {
		return Array.from(this.extensions.values()).reduce(
			(total, ext) => total + ext.metadata.downloads,
			0,
		);
	}
}

/**
 * Image to Code Service
 *
 * Converts UI mockups/screenshots to React components using Kimi K2.5 vision.
 * Uses Moonshot API directly (no proxy needed).
 */

import { analyzeImage, sendKimiMessage, type KimiChatOptions } from './moonshot';

export interface ImageData {
  base64: string;
  mimeType: string;
  url?: string;
}

export interface GeneratedComponent {
  code: string;
  componentName: string;
  dependencies: string[];
  metadata?: {
    responsive?: boolean;
    accessibility?: boolean;
    colors?: string[];
    suggestedComponents?: string[];
  };
}

export interface ComponentGenerationOptions {
  componentName?: string;
  typescript?: boolean;
  styling?: 'tailwind' | 'styled-components' | 'css-modules';
}

export interface DesignSystemAnalysis {
  commonComponents: string[];
  colorPalette: string[];
  typography: { fontFamilies: string[]; sizes: number[] };
  spacing: { scale: number[] };
}

export class ImageToCodeService {
  private cache: Map<string, GeneratedComponent>;
  private cacheExpiry: Map<string, number>;
  private cacheTTL: number;

  constructor(cacheTTL: number = 3600000) {
    this.cache = new Map();
    this.cacheExpiry = new Map();
    this.cacheTTL = cacheTTL;
  }

  async loadImage(pathOrUrl: string): Promise<ImageData> {
    if (pathOrUrl.startsWith('http')) {
      const response = await fetch(pathOrUrl);
      const buffer = await response.arrayBuffer();
      const base64 = this.arrayBufferToBase64(buffer);
      const mimeType = response.headers.get('content-type') ?? 'image/png';
      return { base64, mimeType, url: pathOrUrl };
    }

    // Use Tauri fs for local files
    const { readFile } = await import('@tauri-apps/plugin-fs');
    const content = await readFile(pathOrUrl);
    const base64 = this.uint8ArrayToBase64(content);
    const ext = pathOrUrl.split('.').pop()?.toLowerCase() ?? 'png';
    const mimeType = this.getMimeType(ext);
    return { base64, mimeType };
  }

  async generateComponent(
    imagePath: string,
    options: ComponentGenerationOptions = {},
  ): Promise<GeneratedComponent> {
    const cacheKey = `${imagePath}:${JSON.stringify(options)}`;
    const cached = this.cache.get(cacheKey);
    const expiry = this.cacheExpiry.get(cacheKey);

    if (cached && expiry && Date.now() < expiry) {
      return cached;
    }

    const imageData = await this.loadImage(imagePath);
    const result = await this.callVisionAPI(imageData, options);

    this.cache.set(cacheKey, result);
    this.cacheExpiry.set(cacheKey, Date.now() + this.cacheTTL);

    return result;
  }

  async analyzeDesignSystem(imagePaths: string[]): Promise<DesignSystemAnalysis> {
    // Analyze each image and aggregate results
    const analyses: string[] = [];

    for (const path of imagePaths.slice(0, 5)) {
      // Limit to 5 images
      const imageData = await this.loadImage(path);
      const dataUrl = `data:${imageData.mimeType};base64,${imageData.base64}`;

      const analysis = await analyzeImage(
        dataUrl,
        'Analyze this UI screen. Identify: common UI components (buttons, cards, inputs, etc.), colors used (hex values), font sizes, and spacing patterns. Be specific.',
        { thinking: false },
      );

      analyses.push(analysis);
    }

    // Synthesize all analyses into design system
    const synthesisPrompt = `Based on these UI analyses, extract a unified design system:

${analyses.map((a, i) => `Screen ${i + 1}:\n${a}`).join('\n\n')}

Return a JSON object with:
{
  "commonComponents": ["list", "of", "component", "types"],
  "colorPalette": ["#hex1", "#hex2"],
  "typography": { "fontFamilies": ["fonts"], "sizes": [14, 16, 18] },
  "spacing": { "scale": [4, 8, 16, 24, 32] }
}`;

    const result = await sendKimiMessage(synthesisPrompt, {
      thinking: true,
      systemPrompt: 'You are a design system expert. Return only valid JSON.',
    });

    // Parse JSON from response
    const jsonMatch = result.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        return JSON.parse(jsonMatch[0]);
      } catch {
        // Fall through to defaults
      }
    }

    return {
      commonComponents: [],
      colorPalette: [],
      typography: { fontFamilies: [], sizes: [] },
      spacing: { scale: [] },
    };
  }

  clearCache(): void {
    this.cache.clear();
    this.cacheExpiry.clear();
  }

  getCacheSize(): number {
    return this.cache.size;
  }

  private async callVisionAPI(
    imageData: ImageData,
    options: ComponentGenerationOptions,
  ): Promise<GeneratedComponent> {
    const styling = options.styling ?? 'tailwind';
    const componentName = options.componentName ?? 'GeneratedComponent';
    const useTS = options.typescript !== false;

    const dataUrl = `data:${imageData.mimeType};base64,${imageData.base64}`;

    const prompt = `Convert this UI mockup to a production-ready React component.

Requirements:
- Component name: ${componentName}
- Language: ${useTS ? 'TypeScript' : 'JavaScript'}
- Styling: ${styling}
- Make it responsive
- Include accessibility attributes (aria-labels, roles)
- Use semantic HTML

Return a JSON object with this exact structure:
{
  "code": "// Full component code here",
  "componentName": "${componentName}",
  "dependencies": ["list", "of", "npm", "packages"],
  "metadata": {
    "responsive": true,
    "accessibility": true,
    "colors": ["#hex1", "#hex2"],
    "suggestedComponents": ["Button", "Card"]
  }
}`;

    const kimiOptions: KimiChatOptions = {
      thinking: true,
      maxTokens: 8192,
      systemPrompt:
        'You are an expert React developer. Generate clean, well-documented, production-ready code. Return only valid JSON.',
    };

    const result = await analyzeImage(dataUrl, prompt, kimiOptions);

    // Parse JSON from response
    const jsonMatch = result.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        return JSON.parse(jsonMatch[0]);
      } catch {
        // Fall through to extract code manually
      }
    }

    // Fallback: extract code block if JSON parsing fails
    const codeMatch = result.match(/```(?:tsx?|jsx?)?\n([\s\S]*?)```/);
    return {
      code: codeMatch?.[1] ?? result,
      componentName,
      dependencies: ['react'],
    };
  }

  private getMimeType(ext: string): string {
    const mimeTypes: Record<string, string> = {
      png: 'image/png',
      jpg: 'image/jpeg',
      jpeg: 'image/jpeg',
      gif: 'image/gif',
      webp: 'image/webp',
      svg: 'image/svg+xml',
    };
    return mimeTypes[ext] ?? 'image/png';
  }

  private arrayBufferToBase64(buffer: ArrayBuffer): string {
    const bytes = new Uint8Array(buffer);
    return this.uint8ArrayToBase64(bytes);
  }

  private uint8ArrayToBase64(bytes: Uint8Array): string {
    let binary = '';
    for (let i = 0; i < bytes.byteLength; i++) {
      binary += String.fromCharCode(bytes[i]!);
    }
    return btoa(binary);
  }
}

// Export singleton for convenience
export const imageToCodeService = new ImageToCodeService();

/**
 * LanguageServer
 *
 * Language Server Protocol (LSP) integration for DeepCode Editor
 * Provides IntelliSense, hover, go-to-definition, and diagnostics
 *
 * Based on LSP 3.17 specification and 2025 best practices:
 * - TypeScript/JavaScript language server integration
 * - Document synchronization with version tracking
 * - Code completion with trigger characters
 * - Hover information and definitions
 * - Real-time diagnostics
 */

import { CompletionProvider } from "./languageserver/CompletionProvider";
import { DiagnosticEngine } from "./languageserver/DiagnosticEngine";
import {
	type CompletionContext,
	type CompletionList,
	type Diagnostic,
	type Hover,
	type InitializeParams,
	type Location,
	type Position,
	type ServerCapabilities,
	TextDocument,
	type TextDocumentChange,
} from "./languageserver/types";

// Re-export types for consumers
export * from "./languageserver/types";

export class LanguageServer {
	private languageId: string;
	private running = false;
	private initialized = false;
	private documents = new Map<string, TextDocument>();
	private diagnosticsCallbacks: ((params: {
		uri: string;
		diagnostics: Diagnostic[];
	}) => void)[] = [];
	private capabilities: ServerCapabilities = {};

	private completionProvider: CompletionProvider;
	private diagnosticEngine: DiagnosticEngine;

	constructor(languageId: string) {
		this.languageId = languageId;
		this.completionProvider = new CompletionProvider();
		this.diagnosticEngine = new DiagnosticEngine(languageId);
	}

	/**
	 * Initialize the language server
	 */
	async initialize(params: InitializeParams): Promise<ServerCapabilities> {
		if (!params.rootUri || params.rootUri.trim() === "") {
			throw new Error("Invalid root URI");
		}

		this.initialized = true;

		// Set server capabilities based on language
		this.capabilities = {
			completionProvider: {
				triggerCharacters: [".", ":", "<", '"', "'", "/", "@"],
			},
			hoverProvider: true,
			definitionProvider: true,
			textDocumentSync: 2, // Incremental sync
		};

		return this.capabilities;
	}

	/**
	 * Start the language server
	 */
	async start(): Promise<void> {
		if (!this.initialized) {
			throw new Error("Server not initialized");
		}

		this.running = true;
	}

	/**
	 * Stop the language server
	 */
	async stop(): Promise<void> {
		this.running = false;
	}

	/**
	 * Check if server is running
	 */
	isRunning(): boolean {
		return this.running;
	}

	/**
	 * Get server capabilities
	 */
	getCapabilities(): ServerCapabilities {
		return this.capabilities;
	}

	/**
	 * Open a document
	 */
	openDocument(params: {
		uri: string;
		languageId: string;
		version: number;
		text: string;
	}): void {
		if (!params.uri || params.uri.trim() === "") {
			throw new Error("Invalid document URI");
		}

		const document = TextDocument.create(
			params.uri,
			params.languageId,
			params.version,
			params.text,
		);

		this.documents.set(params.uri, document);

		// Trigger diagnostics
		this.publishDiagnostics(params.uri);
	}

	/**
	 * Change document content
	 */
	changeDocument(params: {
		uri: string;
		version: number;
		changes: TextDocumentChange[];
	}): void {
		const document = this.documents.get(params.uri);
		if (!document) {
			return;
		}

		// Apply changes using TextDocument.update
		const newDocument = TextDocument.update(
			document,
			params.changes,
			params.version,
		);
		this.documents.set(params.uri, newDocument);

		// Trigger diagnostics
		this.publishDiagnostics(params.uri);
	}

	/**
	 * Close a document
	 */
	closeDocument(params: { uri: string }): void {
		this.documents.delete(params.uri);
	}

	/**
	 * Get a document
	 */
	getDocument(uri: string): TextDocument | undefined {
		return this.documents.get(uri);
	}

	/**
	 * Get all documents
	 */
	getAllDocuments(): TextDocument[] {
		return Array.from(this.documents.values());
	}

	/**
	 * Get completions at position
	 */
	async getCompletions(params: {
		uri: string;
		position: Position;
		context?: CompletionContext;
	}): Promise<CompletionList> {
		if (!this.initialized || !this.running) {
			throw new Error("Server not initialized");
		}

		const document = this.documents.get(params.uri);
		if (!document) {
			return { items: [], isIncomplete: false };
		}

		// Generate completions based on context
		const items = this.completionProvider.generateCompletions(
			document,
			params.position,
			params.context,
		);

		return { items, isIncomplete: false };
	}

	/**
	 * Get hover information at position
	 */
	async getHover(params: {
		uri: string;
		position: Position;
	}): Promise<Hover | null> {
		const document = this.documents.get(params.uri);
		if (!document) {
			return null;
		}

		const symbol = this.getSymbolAtPosition(document, params.position);
		if (!symbol) {
			return null;
		}

		return {
			contents: {
				language: this.languageId,
				value: `const ${symbol}: number`,
			},
			range: {
				start: {
					line: params.position.line,
					character: params.position.character - symbol.length,
				},
				end: {
					line: params.position.line,
					character: params.position.character,
				},
			},
		};
	}

	/**
	 * Get definition location
	 */
	async getDefinition(params: {
		uri: string;
		position: Position;
	}): Promise<Location[] | null> {
		const document = this.documents.get(params.uri);
		if (!document) {
			return null;
		}

		const symbol = this.getSymbolAtPosition(document, params.position);
		if (!symbol) {
			return null;
		}

		// Find definition of symbol
		const definitionLine = this.findDefinition(document, symbol);
		if (definitionLine === -1) {
			return null;
		}

		return [
			{
				uri: params.uri,
				range: {
					start: { line: definitionLine, character: 6 },
					end: { line: definitionLine, character: 6 + symbol.length },
				},
			},
		];
	}

	/**
	 * Get diagnostics for document
	 */
	async getDiagnostics(params: { uri: string }): Promise<Diagnostic[]> {
		const document = this.documents.get(params.uri);
		if (!document) {
			return [];
		}

		return this.diagnosticEngine.analyzeDiagnostics(document);
	}

	/**
	 * Register diagnostics callback
	 */
	onDiagnostics(
		callback: (params: { uri: string; diagnostics: Diagnostic[] }) => void,
	): void {
		this.diagnosticsCallbacks.push(callback);
	}

	/**
	 * Dispose all resources
	 */
	dispose(): void {
		this.running = false;
		this.initialized = false;
		this.documents.clear();
		this.diagnosticsCallbacks = [];
	}

	/**
	 * Get symbol at position
	 */
	private getSymbolAtPosition(
		document: TextDocument,
		position: Position,
	): string | null {
		const text = document.getText() ?? "";
		const lines = text.split("\n");
		const line = lines[position.line];

		if (line === undefined) {
			return null;
		}

		// Extract word at position
		const before = line.substring(0, position.character);
		const after = line.substring(position.character);

		const beforeMatch = before.match(/(\w+)$/);
		const afterMatch = after.match(/^(\w+)/);

		if (beforeMatch || afterMatch) {
			return (beforeMatch?.[1] ?? "") + (afterMatch?.[1] ?? "");
		}

		return null;
	}

	/**
	 * Find definition of symbol in document
	 */
	private findDefinition(document: TextDocument, symbol: string): number {
		const text = document.getText() ?? "";
		const lines = text.split("\n");

		for (let i = 0; i < lines.length; i++) {
			const line = lines[i];
			if (line === undefined) continue;
			const constPattern = new RegExp(`const\\s+${symbol}\\s*=`);
			const letPattern = new RegExp(`let\\s+${symbol}\\s*=`);
			const varPattern = new RegExp(`var\\s+${symbol}\\s*=`);

			if (
				constPattern.test(line) ||
				letPattern.test(line) ||
				varPattern.test(line)
			) {
				return i;
			}
		}

		return -1;
	}

	/**
	 * Publish diagnostics to callbacks
	 */
	private publishDiagnostics(uri: string): void {
		setTimeout(async () => {
			const diagnostics = await this.getDiagnostics({ uri });

			for (const callback of this.diagnosticsCallbacks) {
				callback({ uri, diagnostics });
			}
		}, 50);
	}
}

