  return await openRouterClient.chat(request);
}

import { type Child, Command } from "@tauri-apps/plugin-shell";
import { FitAddon } from "@xterm/addon-fit";
import { SearchAddon } from "@xterm/addon-search";
import { type ITheme, Terminal } from "@xterm/xterm";
import type { TerminalOptions } from "./types";

export class TerminalSession {
	public id: string;
	public instance: Terminal;
	public fitAddon: FitAddon;
	public searchAddon: SearchAddon;
	public process?: Child;
	public createdAt: Date;

	public readonly options: TerminalOptions;
	private dataHandlers: ((data: string) => void)[] = [];
	private exitHandlers: ((code: number) => void)[] = [];

	constructor(id: string, options: TerminalOptions) {
		this.id = id;
		this.options = options;
		this.createdAt = new Date();

		// Create xterm instance
		this.instance = new Terminal({
			rows: options.rows ?? 30,
			cols: options.cols ?? 80,
			fontSize: options.fontSize ?? 14,
			fontFamily: options.fontFamily ?? "Cascadia Code, Consolas, monospace",
			theme: options.theme ?? this.getDefaultTheme(),
			cursorBlink: true,
			cursorStyle: "block",
			scrollback: 1000,
			allowTransparency: false,
			convertEol: true,
			...options,
		});

		this.fitAddon = new FitAddon();
		this.searchAddon = new SearchAddon();
		this.instance.loadAddon(this.fitAddon);
		this.instance.loadAddon(this.searchAddon);
	}

	/**
	 * Initialize and spawn the shell process
	 */
	async spawn(): Promise<void> {
		const shell = this.options.shell ?? "powershell.exe";

		// Tauri Command
		// Note: 'powershell' must be allowed in tauri.conf.json > capabilities
		const cmd = Command.create(shell, []);

		// Setup event listeners before spawn
		cmd.on("close", (data) => {
			this.exitHandlers.forEach((h) => h(data.code ?? 0));
			this.process = undefined;
		});

		cmd.on("error", (error) => console.error(`command error: "${error}"`));

		cmd.stdout.on("data", (line) => {
			this.instance.write(line);
			this.dataHandlers.forEach((h) => h(line));
		});

		cmd.stderr.on("data", (line) => {
			this.instance.write(line);
			this.dataHandlers.forEach((h) => h(line));
		});

		try {
			this.process = await cmd.spawn();

			// Forward terminal input to process
			this.instance.onData((data) => {
				if (this.process) {
					this.process.write(data);
				}
			});
		} catch (err) {
			this.instance.write(
				`\r\n\x1b[31mFailed to launch shell: ${err}\x1b[0m\r\n`,
			);
			throw err;
		}
	}

	write(data: string): void {
		this.instance.write(data);
		this.process?.write(data);
	}

	resize(cols: number, rows: number): void {
		this.instance.resize(cols, rows);
		this.fitAddon.fit();
		// Note: Tauri Shell plugin currently doesn't support explicit resize signals
		// to the PTY in the same way node-pty does, but usually it handles flow well enough.
	}

	kill(): void {
		this.process?.kill();
	}

	onData(handler: (data: string) => void): void {
		this.dataHandlers.push(handler);
	}

	onExit(handler: (code: number) => void): void {
		this.exitHandlers.push(handler);
	}

	search(query: string): boolean {
		const result = this.searchAddon.findNext(query);
		if (!result) {
			// Simple manual buffer check fallback
			const buffer = this.instance.buffer.active;
			for (let i = 0; i < buffer.length; i++) {
				if (buffer.getLine(i)?.translateToString(true).includes(query)) {
					return true;
				}
			}
		}
		return result;
	}

	dispose(): void {
		this.kill();
		this.instance.dispose();
	}

	private getDefaultTheme(): ITheme {
		return {
			background: "#1e1e1e",
			foreground: "#cccccc",
			cursor: "#ffffff",
			black: "#000000",
			red: "#cd3131",
			green: "#0dbc79",
			yellow: "#e5e510",
			blue: "#2472c8",
			magenta: "#bc3fbc",
			cyan: "#11a8cd",
			white: "#e5e5e5",
			brightBlack: "#666666",
			brightRed: "#f14c4c",
			brightGreen: "#23d18b",
			brightYellow: "#f5f543",
			brightBlue: "#3b8eea",
			brightMagenta: "#d670d6",
			brightCyan: "#29b8db",
			brightWhite: "#ffffff",
		};
	}
}

/**
 * Vision Analysis Service
 *
 * Provides screenshot analysis using Kimi K2.5 via Moonshot API.
 * Supports multimodal input (image + text) for UI analysis, debugging, and extraction.
 */

import { analyzeImage, type KimiChatOptions } from './moonshot';

export interface VisionAnalysisOptions {
  prompt?: string;
  thinking?: boolean;
  maxTokens?: number;
}

export interface VisionAnalysisResult {
  analysis: string;
  timestamp: number;
  model: string;
}

/**
 * Read image file and convert to base64
 */
async function readImageAsBase64(imagePath: string): Promise<string> {
  const { readFile } = await import('@tauri-apps/plugin-fs');
  const imageData = await readFile(imagePath);

  // Convert Uint8Array to base64
  const base64 = btoa(
    Array.from(imageData)
      .map((byte) => String.fromCharCode(byte))
      .join(''),
  );

  return base64;
}

/**
 * Determine MIME type from file extension
 */
function getMimeType(imagePath: string): string {
  const ext = imagePath.split('.').pop()?.toLowerCase();

  const mimeTypes: Record<string, string> = {
    png: 'image/png',
    jpg: 'image/jpeg',
    jpeg: 'image/jpeg',
    gif: 'image/gif',
    webp: 'image/webp',
  };

  return mimeTypes[ext ?? 'png'] ?? 'image/png';
}

/**
 * Analyze a screenshot using Kimi K2.5 vision capabilities
 *
 * @param imagePath - Absolute path to the screenshot file
 * @param options - Analysis options
 * @returns Analysis result with extracted insights
 */
export async function analyzeScreenshot(
  imagePath: string,
  options: VisionAnalysisOptions = {},
): Promise<VisionAnalysisResult> {
  const {
    prompt = 'Analyze this screenshot. Describe what you see, identify any UI elements, text, or issues.',
    thinking = false,
    maxTokens = 4096,
  } = options;

  // Read image and convert to base64 data URL
  const base64Image = await readImageAsBase64(imagePath);
  const mimeType = getMimeType(imagePath);
  const dataUrl = `data:${mimeType};base64,${base64Image}`;

  // Call Kimi K2.5 with vision
  const kimiOptions: KimiChatOptions = {
    thinking,
    maxTokens,
  };

  const analysis = await analyzeImage(dataUrl, prompt, kimiOptions);

  return {
    analysis,
    timestamp: Date.now(),
    model: 'kimi-k2.5',
  };
}

/**
 * Analyze screenshot for specific purpose (UI debugging, accessibility, design review)
 */
export async function analyzeScreenshotWithContext(
  imagePath: string,
  context: 'ui-debug' | 'accessibility' | 'design-review',
  customPrompt?: string,
): Promise<VisionAnalysisResult> {
  const prompts = {
    'ui-debug':
      customPrompt ||
      'Analyze this UI screenshot for potential bugs, layout issues, alignment problems, or visual inconsistencies. ' +
        'Identify any elements that appear broken or incorrectly rendered.',

    accessibility:
      customPrompt ||
      'Review this screenshot for accessibility issues. Check for: ' +
        '- Sufficient color contrast\n' +
        '- Text readability\n' +
        '- Clickable element sizes\n' +
        '- Missing labels or alt text indicators\n' +
        'Provide actionable recommendations.',

    'design-review':
      customPrompt ||
      'Perform a design review of this screenshot. Evaluate: ' +
        '- Visual hierarchy\n' +
        '- Spacing and alignment\n' +
        '- Typography consistency\n' +
        '- Color scheme\n' +
        '- Overall aesthetic quality\n' +
        'Suggest improvements.',
  };

  return analyzeScreenshot(imagePath, {
    prompt: prompts[context],
    thinking: true, // Use thinking for thorough analysis
  });
}

/**
 * Extract text from screenshot using OCR-like capabilities
 */
export async function extractTextFromScreenshot(imagePath: string): Promise<string> {
  const result = await analyzeScreenshot(imagePath, {
    prompt:
      'Extract all visible text from this screenshot. ' +
      'Provide the text in the order it appears, preserving structure where possible.',
  });

  return result.analysis;
}

/**
 * Compare two screenshots and identify differences
 */
export async function compareScreenshots(
  beforePath: string,
  afterPath: string,
): Promise<VisionAnalysisResult> {
  // Read both images
  const beforeBase64 = await readImageAsBase64(beforePath);
  const afterBase64 = await readImageAsBase64(afterPath);

  const beforeMime = getMimeType(beforePath);
  const afterMime = getMimeType(afterPath);

  // Create combined prompt with both images described
  // Note: Kimi K2.5 handles single image per request, so we'll analyze sequentially
  const beforeDataUrl = `data:${beforeMime};base64,${beforeBase64}`;
  const afterDataUrl = `data:${afterMime};base64,${afterBase64}`;

  // Analyze BEFORE
  const beforeAnalysis = await analyzeImage(
    beforeDataUrl,
    'Describe this UI screenshot in detail. Note all visible elements, text, layout, and styling.',
    { thinking: false },
  );

  // Analyze AFTER with context of BEFORE
  const comparison = await analyzeImage(
    afterDataUrl,
    `Compare this screenshot to the previous state described below and identify all differences:\n\nPREVIOUS STATE:\n${beforeAnalysis}\n\nList all visual differences, changes in layout, text modifications, or any other variations.`,
    { thinking: true },
  );

  return {
    analysis: comparison,
    timestamp: Date.now(),
    model: 'kimi-k2.5',
  };
}

import type { LazyExoticComponent } from "react";
import { type ComponentType, createElement, lazy } from "react";

export function lazyLoad<T extends ComponentType<any>>(
	factory: () => Promise<{ default: T }>,
	minLoadTimeMs = 0,
): LazyExoticComponent<T> {
	return lazy(() =>
		Promise.all([
			factory(),
			new Promise<void>((resolve) => setTimeout(resolve, minLoadTimeMs)),
		]).then(([moduleExports]) => moduleExports),
	);
}

type LazyLoader<TProps> = () => Promise<{ default: ComponentType<TProps> }>;

interface LazyComponentOptions {
	minDelayMs?: number;
}

function withMinDelay<T>(promise: Promise<T>, minDelayMs?: number): Promise<T> {
	if (!minDelayMs || minDelayMs <= 0) return promise;
	return Promise.all([
		promise,
		new Promise<void>((resolve) => setTimeout(resolve, minDelayMs)),
	]).then(([value]) => value);
}

export function createLazyComponent<TProps>(
	loader: LazyLoader<TProps>,
	displayName: string,
	options: LazyComponentOptions = {},
): ComponentType<TProps> {
	const Lazy = lazy(() => withMinDelay(loader(), options.minDelayMs));
	const Wrapped = (props: TProps) => createElement(Lazy as any, props as any);
	Wrapped.displayName = `Lazy(${displayName})`;
	return Wrapped;
}

export function createLazyHeavyComponent<TProps>(
	loader: LazyLoader<TProps>,
	displayName: string,
	minDelayMs = 250,
): ComponentType<TProps> {
	return createLazyComponent(loader, displayName, { minDelayMs });
}

type RoutePriority = "high" | "medium" | "low";

interface LazyRouteOptions {
	priority?: RoutePriority;
	preload?: boolean;
	dependencies?: string[];
}

interface RouteRegistryEntry {
	name: string;
	loader: () => Promise<unknown>;
	options: LazyRouteOptions;
}

const routeRegistry = new Map<string, RouteRegistryEntry>();
const actionHistory: string[] = [];
const preloadCallbacks = new Map<string, Array<() => void>>();

export const globalPreloader = {
	registerRoute(
		name: string,
		loader: () => Promise<unknown>,
		options: LazyRouteOptions = {},
	) {
		routeRegistry.set(name, { name, loader, options });
		if (options.preload) {
			void loader();
		}
	},

	preload(name: string) {
		const entry = routeRegistry.get(name);
		if (!entry) return;
		void entry.loader();
	},

	recordAction(action: string) {
		actionHistory.push(action);
		if (actionHistory.length > 100) actionHistory.shift();

		// Trigger callbacks registered for this action
		const callbacks = preloadCallbacks.get(action);
		if (callbacks) {
			callbacks.forEach((cb) => cb());
		}
	},

	registerPreloadCallback(action: string, callback: () => void) {
		if (!preloadCallbacks.has(action)) {
			preloadCallbacks.set(action, []);
		}
		preloadCallbacks.get(action)?.push(callback);
	},
};

export function createLazyRoute<TProps>(
	loader: LazyLoader<TProps>,
	routeName: string,
	options: LazyRouteOptions = {},
): ComponentType<TProps> {
	globalPreloader.registerRoute(routeName, () => loader(), options);
	return createLazyComponent(loader, routeName);
}

